{
  "name": "BeautySynth Pro Studio",
  "description": "A professional AI-powered beauty studio for facial feature modification, makeup artistry, and hairstyle visualization using Gemini 3.0 Pro.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface FacialFeatures {
  eyeSize: number;
  lipThickness: number;
  noseWidth: number;
  doubleEyelid: boolean;
  jawlineSharpness: number;
}

export interface SkinFeatures {
  tone: string;
  texture: string[]; // freckles, acne, smooth, etc.
}

export interface StyleFeatures {
  hairStyle: string;
  hairColor: string;
  makeupStyle: string;
}

export interface StudioState {
  baseImage: string | null;
  referenceImage: string | null;
  features: FacialFeatures;
  skin: SkinFeatures;
  style: StyleFeatures;
}

export enum TabType {
  FEATURES = 'FEATURES',
  SKIN = 'SKIN',
  STYLE = 'STYLE'
}

declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

export const SKIN_TONES = [
  { id: 'porcelain', label: 'Porcelain', color: '#f8ece0' },
  { id: 'fair', label: 'Fair', color: '#f3e5d0' },
  { id: 'natural', label: 'Natural', color: '#e6c8a9' },
  { id: 'tanned', label: 'Tanned', color: '#c68e62' },
  { id: 'deep', label: 'Deep', color: '#8d5524' }
];

export const SKIN_TEXTURES = [
  'Smooth', 'Freckles', 'Acne-prone', 'Glass Skin', 'Mole', 'Radiant'
];

export const HAIR_STYLES = [
  'Long Wavy', 'Short Pixie', 'Bob Cut', 'Ponytail', 'Straight Long', 'Curtain Bangs', 'Buzz Cut'
];

export const MAKEUP_STYLES = [
  'Natural', 'Glitter', 'Smoky Eye', 'K-Beauty', 'Vintage', 'High Fashion', 'No Makeup'
];

export const INITIAL_FEATURES = {
  eyeSize: 50,
  lipThickness: 50,
  noseWidth: 50,
  doubleEyelid: true,
  jawlineSharpness: 50
};

import React, { useState, useEffect, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage } from './services/geminiService';
import { StudioState, TabType } from './types';
import { INITIAL_FEATURES } from './constants';
import { Sparkles, Camera, Upload, Trash2, Zap } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    baseImage: null,
    referenceImage: null,
    features: INITIAL_FEATURES,
    skin: { tone: 'natural', texture: ['Smooth'] },
    style: { hairStyle: 'Long Wavy', hairColor: 'Black', makeupStyle: 'Natural' }
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>(TabType.FEATURES);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);

      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
      } else {
        setError("Failed to generate image. Please try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setIsGenerating(false);
    }
  };

  const updateState = (updates: Partial<StudioState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const onFileUpload = (type: 'base' | 'reference') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') updateState({ baseImage: base64String });
        else updateState({ referenceImage: base64String });
      };
      reader.readAsDataURL(file);
    }
  };

  if (needsKey) {
    return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;
  }

  return (
    <div className="flex flex-col h-screen bg-zinc-950 overflow-hidden text-zinc-100">
      {/* Header */}
      <header className="h-16 border-b border-zinc-800 flex items-center justify-between px-6 bg-zinc-900/50 backdrop-blur-md">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
            <Sparkles className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">BeautySynth <span className="text-indigo-500">Pro</span></h1>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={handleGenerate}
            disabled={isGenerating}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-full font-semibold transition-all shadow-lg shadow-indigo-500/10 ${
              isGenerating 
              ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed' 
              : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95'
            }`}
          >
            {isGenerating ? (
              <>
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                Generating 2K Studio...
              </>
            ) : (
              <>
                <Zap className="w-4 h-4 fill-current" />
                Generate Synthesis
              </>
            )}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        {/* Sidebar Controls */}
        <StudioSidebar 
          state={state} 
          updateState={updateState} 
          activeTab={activeTab} 
          setActiveTab={setActiveTab} 
        />

        {/* Workspace */}
        <div className="flex-1 p-6 flex flex-col gap-6 overflow-y-auto bg-zinc-950">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-4 rounded-xl flex items-center justify-between">
              <span>{error}</span>
              <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">✕</button>
            </div>
          )}

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 h-full min-h-[500px]">
            {/* Input Section */}
            <div className="space-y-6 flex flex-col">
              <div className="flex-1 bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden flex flex-col relative group">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
                  <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider">Base Face Image</h3>
                  {state.baseImage && (
                    <button onClick={() => updateState({ baseImage: null })} className="p-1 hover:text-red-400 transition-colors">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
                <div className="flex-1 flex items-center justify-center relative">
                  {state.baseImage ? (
                    <img src={state.baseImage} className="w-full h-full object-contain" alt="Base" />
                  ) : (
                    <label className="cursor-pointer group flex flex-col items-center gap-4">
                      <div className="w-16 h-16 rounded-full bg-zinc-800 flex items-center justify-center group-hover:bg-zinc-700 transition-colors">
                        <Upload className="w-8 h-8 text-zinc-500" />
                      </div>
                      <div className="text-center">
                        <p className="text-zinc-400 font-medium">Click to upload base model</p>
                        <p className="text-zinc-600 text-sm mt-1">Portrait orientation recommended</p>
                      </div>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
              </div>

              <div className="h-48 bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden flex flex-col relative">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
                  <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider">Reference Style (Optional)</h3>
                  {state.referenceImage && (
                    <button onClick={() => updateState({ referenceImage: null })} className="p-1 hover:text-red-400 transition-colors">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
                <div className="flex-1 flex items-center justify-center">
                  {state.referenceImage ? (
                    <img src={state.referenceImage} className="w-full h-full object-cover" alt="Reference" />
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-2">
                      <Camera className="w-6 h-6 text-zinc-600" />
                      <span className="text-zinc-500 text-sm">Add Style Ref</span>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('reference')} />
                    </label>
                  )}
                </div>
              </div>
            </div>

            {/* Output Section */}
            <div className="bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden flex flex-col shadow-2xl shadow-black">
              <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
                <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider">Generated Result (2K)</h3>
                {generatedImage && (
                  <a 
                    href={generatedImage} 
                    download="beauty-synth-studio.png" 
                    className="text-xs text-indigo-400 hover:text-indigo-300 font-medium uppercase tracking-tighter"
                  >
                    Download HD
                  </a>
                )}
              </div>
              <div className="flex-1 bg-zinc-950 relative overflow-hidden group">
                <PreviewCanvas image={generatedImage} loading={isGenerating} />
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { StudioState, TabType } from '../types';
import { SKIN_TONES, SKIN_TEXTURES, HAIR_STYLES, MAKEUP_STYLES } from '../constants';
import { User, Droplets, Palette, Scissors } from 'lucide-react';

interface SidebarProps {
  state: StudioState;
  updateState: (updates: Partial<StudioState>) => void;
  activeTab: TabType;
  setActiveTab: (tab: TabType) => void;
}

export const StudioSidebar: React.FC<SidebarProps> = ({ state, updateState, activeTab, setActiveTab }) => {
  const handleFeatureChange = (key: string, value: any) => {
    updateState({ features: { ...state.features, [key]: value } });
  };

  const handleSkinChange = (key: string, value: any) => {
    updateState({ skin: { ...state.skin, [key]: value } });
  };

  const handleStyleChange = (key: string, value: any) => {
    updateState({ style: { ...state.style, [key]: value } });
  };

  return (
    <aside className="w-80 border-r border-zinc-800 bg-zinc-900 flex flex-col h-full">
      {/* Tabs */}
      <div className="flex border-b border-zinc-800">
        {[
          { id: TabType.FEATURES, icon: User, label: 'Face' },
          { id: TabType.SKIN, icon: Droplets, label: 'Skin' },
          { id: TabType.STYLE, icon: Scissors, label: 'Style' }
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex-1 py-4 flex flex-col items-center gap-1 transition-colors ${
              activeTab === tab.id ? 'text-indigo-500 bg-zinc-800/50' : 'text-zinc-500 hover:text-zinc-300'
            }`}
          >
            <tab.icon className="w-5 h-5" />
            <span className="text-[10px] font-bold uppercase tracking-widest">{tab.label}</span>
          </button>
        ))}
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-8">
        {activeTab === TabType.FEATURES && (
          <div className="space-y-6">
            <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-widest">Facial Proportions</h4>

            <div className="space-y-4">
              <div className="space-y-2">
                <div className="flex justify-between text-xs font-medium">
                  <span className="text-zinc-400">Eye Size</span>
                  <span className="text-indigo-400">{state.features.eyeSize}%</span>
                </div>
                <input 
                  type="range" min="0" max="100" 
                  value={state.features.eyeSize}
                  onChange={(e) => handleFeatureChange('eyeSize', parseInt(e.target.value))}
                  className="w-full accent-indigo-600 h-1.5 bg-zinc-800 rounded-lg appearance-none cursor-pointer" 
                />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-xs font-medium">
                  <span className="text-zinc-400">Lip Thickness</span>
                  <span className="text-indigo-400">{state.features.lipThickness}%</span>
                </div>
                <input 
                  type="range" min="0" max="100" 
                  value={state.features.lipThickness}
                  onChange={(e) => handleFeatureChange('lipThickness', parseInt(e.target.value))}
                  className="w-full accent-indigo-600 h-1.5 bg-zinc-800 rounded-lg appearance-none cursor-pointer" 
                />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-xs font-medium">
                  <span className="text-zinc-400">Nose Width</span>
                  <span className="text-indigo-400">{state.features.noseWidth}%</span>
                </div>
                <input 
                  type="range" min="0" max="100" 
                  value={state.features.noseWidth}
                  onChange={(e) => handleFeatureChange('noseWidth', parseInt(e.target.value))}
                  className="w-full accent-indigo-600 h-1.5 bg-zinc-800 rounded-lg appearance-none cursor-pointer" 
                />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-xs font-medium">
                  <span className="text-zinc-400">Jawline Sharpness</span>
                  <span className="text-indigo-400">{state.features.jawlineSharpness}%</span>
                </div>
                <input 
                  type="range" min="0" max="100" 
                  value={state.features.jawlineSharpness}
                  onChange={(e) => handleFeatureChange('jawlineSharpness', parseInt(e.target.value))}
                  className="w-full accent-indigo-600 h-1.5 bg-zinc-800 rounded-lg appearance-none cursor-pointer" 
                />
              </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-zinc-800">
              <span className="text-sm font-medium text-zinc-300">Double Eyelid</span>
              <button 
                onClick={() => handleFeatureChange('doubleEyelid', !state.features.doubleEyelid)}
                className={`w-11 h-6 rounded-full transition-colors relative ${state.features.doubleEyelid ? 'bg-indigo-600' : 'bg-zinc-700'}`}
              >
                <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform ${state.features.doubleEyelid ? 'translate-x-5' : 'translate-x-0'}`} />
              </button>
            </div>
          </div>
        )}

        {activeTab === TabType.SKIN && (
          <div className="space-y-8">
            <div className="space-y-4">
              <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-widest">Tone Selection</h4>
              <div className="flex flex-wrap gap-3">
                {SKIN_TONES.map(tone => (
                  <button
                    key={tone.id}
                    onClick={() => handleSkinChange('tone', tone.id)}
                    className={`group flex flex-col items-center gap-2 p-1 rounded-lg transition-all ${state.skin.tone === tone.id ? 'ring-2 ring-indigo-500 bg-zinc-800' : 'hover:bg-zinc-800'}`}
                  >
                    <div className="w-10 h-10 rounded-full border border-zinc-700 shadow-inner" style={{ backgroundColor: tone.color }} />
                    <span className="text-[10px] text-zinc-400 font-medium group-hover:text-zinc-200">{tone.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-widest">Texture & Details</h4>
              <div className="grid grid-cols-2 gap-2">
                {SKIN_TEXTURES.map(texture => (
                  <button
                    key={texture}
                    onClick={() => {
                      const newTextures = state.skin.texture.includes(texture)
                        ? state.skin.texture.filter(t => t !== texture)
                        : [...state.skin.texture, texture];
                      handleSkinChange('texture', newTextures);
                    }}
                    className={`px-3 py-2 rounded-lg text-xs font-medium border transition-all ${
                      state.skin.texture.includes(texture)
                      ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400'
                      : 'bg-zinc-800/50 border-zinc-700 text-zinc-400 hover:border-zinc-600'
                    }`}
                  >
                    {texture}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {activeTab === TabType.STYLE && (
          <div className="space-y-8">
            <div className="space-y-4">
              <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-widest">Hairstyle</h4>
              <div className="grid grid-cols-1 gap-2">
                {HAIR_STYLES.map(style => (
                  <button
                    key={style}
                    onClick={() => handleStyleChange('hairStyle', style)}
                    className={`w-full px-4 py-2 text-left rounded-lg text-sm border transition-all ${
                      state.style.hairStyle === style
                      ? 'bg-indigo-600 border-indigo-500 text-white'
                      : 'bg-zinc-800/50 border-zinc-700 text-zinc-400 hover:bg-zinc-800 hover:border-zinc-600'
                    }`}
                  >
                    {style}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-widest">Makeup Concept</h4>
              <select 
                value={state.style.makeupStyle}
                onChange={(e) => handleStyleChange('makeupStyle', e.target.value)}
                className="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-4 py-2 text-sm text-zinc-200 outline-none focus:border-indigo-500 transition-colors"
              >
                {MAKEUP_STYLES.map(style => (
                  <option key={style} value={style}>{style}</option>
                ))}
              </select>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 border-t border-zinc-800 bg-zinc-900/50">
        <div className="p-3 bg-zinc-800/50 rounded-xl border border-zinc-700/50">
          <div className="flex items-center gap-2 mb-2 text-amber-400">
            <Zap className="w-3 h-3 fill-current" />
            <span className="text-[10px] font-bold uppercase tracking-widest">Pro Rendering</span>
          </div>
          <p className="text-[10px] text-zinc-500 leading-relaxed">
            All transformations are processed via Gemini 3.0 Pro Image for superior clarity and aesthetic balance at 2K resolution.
          </p>
        </div>
      </div>
    </aside>
  );
};

import React from 'react';
import { Loader2, Maximize2 } from 'lucide-react';

interface PreviewProps {
  image: string | null;
  loading: boolean;
}

export const PreviewCanvas: React.FC<PreviewProps> = ({ image, loading }) => {
  return (
    <div className="w-full h-full relative group">
      {loading && (
        <div className="absolute inset-0 z-50 bg-zinc-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-6">
          <div className="relative">
            <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
            <div className="absolute inset-0 blur-xl bg-indigo-500/20 animate-pulse" />
          </div>
          <div className="text-center space-y-2">
            <h3 className="text-lg font-semibold text-white">Synthesizing Beauty...</h3>
            <p className="text-zinc-500 text-sm max-w-[200px] mx-auto animate-pulse">
              Gemini is calculating facial symmetry and high-resolution textures.
            </p>
          </div>
        </div>
      )}

      {image ? (
        <>
          <img src={image} className="w-full h-full object-contain" alt="Generated Beauty" />
          <button className="absolute bottom-4 right-4 p-2 bg-black/50 backdrop-blur-md rounded-lg text-white opacity-0 group-hover:opacity-100 transition-opacity">
            <Maximize2 className="w-5 h-5" />
          </button>
        </>
      ) : !loading && (
        <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center gap-4">
          <div className="w-20 h-20 rounded-3xl bg-zinc-900 border border-zinc-800 flex items-center justify-center">
            <span className="text-3xl font-bold text-zinc-700">?</span>
          </div>
          <div className="space-y-1">
            <h3 className="text-zinc-300 font-medium">No synthesis generated yet</h3>
            <p className="text-zinc-500 text-sm">Upload a base model and click generate to see the results.</p>
          </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { Key, ExternalLink } from 'lucide-react';

interface ApiKeyModalProps {
  onComplete: () => void;
}

export const ApiKeyModal: React.FC<ApiKeyModalProps> = ({ onComplete }) => {
  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      onComplete(); // Assume success as per guidelines
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-zinc-950 flex items-center justify-center p-6">
      <div className="max-w-md w-full bg-zinc-900 border border-zinc-800 rounded-3xl p-8 shadow-2xl space-y-8">
        <div className="flex flex-col items-center text-center gap-4">
          <div className="w-16 h-16 bg-indigo-500/10 rounded-full flex items-center justify-center text-indigo-500">
            <Key className="w-8 h-8" />
          </div>
          <div className="space-y-2">
            <h2 className="text-2xl font-bold text-white">API Key Required</h2>
            <p className="text-zinc-400 text-sm leading-relaxed">
              BeautySynth Pro utilizes Gemini 3.0 Pro for 2K high-fidelity image synthesis. To proceed, please select your authorized API key.
            </p>
          </div>
        </div>

        <div className="space-y-4">
          <button
            onClick={handleSelectKey}
            className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-indigo-600/20 active:scale-[0.98]"
          >
            Select API Key
          </button>

          <a 
            href="https://ai.google.dev/gemini-api/docs/billing" 
            target="_blank" 
            rel="noopener noreferrer"
            className="flex items-center justify-center gap-2 text-xs text-zinc-500 hover:text-zinc-300 font-medium transition-colors"
          >
            Billing Information <ExternalLink className="w-3 h-3" />
          </a>
        </div>

        <div className="pt-4 border-t border-zinc-800/50">
          <p className="text-[10px] text-zinc-600 text-center uppercase tracking-widest font-bold">
            Secured Synthesis Environment
          </p>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import { StudioState } from "../types";

export const generateBeautyImage = async (state: StudioState): Promise<string | null> => {
  // Always create a new instance to get latest key from environment
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Construct descriptive prompt
  const featuresText = [
    state.features.eyeSize > 60 ? "large expressive eyes" : (state.features.eyeSize < 40 ? "slender elegant eyes" : "well-proportioned eyes"),
    state.features.lipThickness > 60 ? "full voluminous lips" : (state.features.lipThickness < 40 ? "thin refined lips" : "balanced lips"),
    state.features.noseWidth > 60 ? "broad nose" : (state.features.noseWidth < 40 ? "slim narrow nose" : "proportionate nose"),
    state.features.doubleEyelid ? "distinct double eyelids" : "clean monolid eye look",
    state.features.jawlineSharpness > 70 ? "very sharp defined jawline" : "soft natural jawline contour"
  ].join(", ");

  const skinText = `The skin should have a ${state.skin.tone} tone with ${state.skin.texture.join(" and ")} characteristics.`;
  const styleText = `Featuring a ${state.style.hairStyle} in a natural hue. The makeup style is ${state.style.makeupStyle}.`;

  const prompt = `High-end professional beauty studio photography of a face. 
    MODIFICATIONS: ${featuresText}. 
    SKIN: ${skinText}. 
    STYLE: ${styleText}. 
    QUALITY: Extremely high detail, realistic skin texture, 8k resolution look, studio lighting, bokeh background, cinematic makeup photography. 
    Maintain facial structural identity if a base image is provided.`;

  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({
      inlineData: {
        data: baseData,
        mimeType: mimeType
      }
    });
  }

  if (state.referenceImage) {
    const refData = state.referenceImage.split(',')[1];
    const mimeType = state.referenceImage.split(';')[0].split(':')[1];
    parts.push({
      inlineData: {
        data: refData,
        mimeType: mimeType
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

