import React, { useState, useEffect, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage } from './services/geminiService';
import { StudioState, TabType } from './types';
import { INITIAL_FEATURES } from './constants';
import { Sparkles, Camera, Upload, Trash2, Zap } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    baseImage: null,
    referenceImage: null,
    features: INITIAL_FEATURES,
    skin: { tone: 'natural', texture: ['Smooth'] },
    style: { hairStyle: 'Long Wavy', hairColor: 'Black', makeupStyle: 'Natural' },
    aspectRatio: '1:1'
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>(TabType.FEATURES);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);

      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
      } else {
        setError("Failed to generate image. Please try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setIsGenerating(false);
    }
  };

  const updateState = (updates: Partial<StudioState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const calculateAspectRatio = (img: HTMLImageElement): "1:1" | "3:4" | "4:3" | "9:16" | "16:9" => {
    const ratio = img.width / img.height;
    const options: { label: "1:1" | "3:4" | "4:3" | "9:16" | "16:9", value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];

    return options.reduce((prev, curr) => 
      Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev
    ).label;
  };

  const onFileUpload = (type: 'base' | 'reference') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = () => {
            const ratio = calculateAspectRatio(img);
            updateState({ baseImage: base64String, aspectRatio: ratio });
          };
          img.src = base64String;
        } else {
          updateState({ referenceImage: base64String });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  if (needsKey) {
    return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;
  }

  return (
    <div className="flex flex-col h-screen bg-zinc-950 overflow-hidden text-zinc-100">
      {/* Header */}
      <header className="h-16 border-b border-zinc-800 flex items-center justify-between px-6 bg-zinc-900/50 backdrop-blur-md">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
            <Sparkles className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">BeautySynth <span className="text-indigo-500">Pro</span></h1>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={handleGenerate}
            disabled={isGenerating}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-full font-semibold transition-all shadow-lg shadow-indigo-500/10 ${
              isGenerating 
              ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed' 
              : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95'
            }`}
          >
            {isGenerating ? (
              <>
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                Generating 2K Studio...
              </>
            ) : (
              <>
                <Zap className="w-4 h-4 fill-current" />
                Generate Synthesis
              </>
            )}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        {/* Sidebar Controls */}
        <StudioSidebar 
          state={state} 
          updateState={updateState} 
          activeTab={activeTab} 
          setActiveTab={setActiveTab} 
        />

        {/* Workspace */}
        <div className="flex-1 p-6 flex flex-col gap-6 overflow-y-auto bg-zinc-950">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-4 rounded-xl flex items-center justify-between">
              <span>{error}</span>
              <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">✕</button>
            </div>
          )}

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 h-full min-h-[500px]">
            {/* Input Section */}
            <div className="space-y-6 flex flex-col">
              <div className="flex-1 bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden flex flex-col relative group">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
                  <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider">Base Face Image</h3>
                  {state.baseImage && (
                    <button onClick={() => updateState({ baseImage: null })} className="p-1 hover:text-red-400 transition-colors">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
                <div className="flex-1 flex items-center justify-center relative">
                  {state.baseImage ? (
                    <img src={state.baseImage} className="w-full h-full object-contain" alt="Base" />
                  ) : (
                    <label className="cursor-pointer group flex flex-col items-center gap-4">
                      <div className="w-16 h-16 rounded-full bg-zinc-800 flex items-center justify-center group-hover:bg-zinc-700 transition-colors">
                        <Upload className="w-8 h-8 text-zinc-500" />
                      </div>
                      <div className="text-center">
                        <p className="text-zinc-400 font-medium">Click to upload base model</p>
                        <p className="text-zinc-600 text-sm mt-1">Detects aspect ratio automatically</p>
                      </div>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
                {state.baseImage && (
                  <div className="absolute bottom-2 left-2 px-2 py-1 bg-black/60 backdrop-blur rounded text-[10px] font-bold text-zinc-400 border border-zinc-800">
                    RATIO: {state.aspectRatio}
                  </div>
                )}
              </div>

              <div className="h-48 bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden flex flex-col relative">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
                  <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider">Reference Style (Optional)</h3>
                  {state.referenceImage && (
                    <button onClick={() => updateState({ referenceImage: null })} className="p-1 hover:text-red-400 transition-colors">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
                <div className="flex-1 flex items-center justify-center">
                  {state.referenceImage ? (
                    <img src={state.referenceImage} className="w-full h-full object-cover" alt="Reference" />
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-2">
                      <Camera className="w-6 h-6 text-zinc-600" />
                      <span className="text-zinc-500 text-sm">Add Style Ref</span>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('reference')} />
                    </label>
                  )}
                </div>
              </div>
            </div>

            {/* Output Section */}
            <div className="bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden flex flex-col shadow-2xl shadow-black">
              <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
                <h3 className="text-sm font-medium text-zinc-400 uppercase tracking-wider">Generated Result (2K)</h3>
                {generatedImage && (
                  <a 
                    href={generatedImage} 
                    download="beauty-synth-studio.png" 
                    className="text-xs text-indigo-400 hover:text-indigo-300 font-medium uppercase tracking-tighter"
                  >
                    Download HD
                  </a>
                )}
              </div>
              <div className="flex-1 bg-zinc-950 relative overflow-hidden group">
                <PreviewCanvas image={generatedImage} loading={isGenerating} />
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { StudioState } from "../types";

export const generateBeautyImage = async (state: StudioState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const featuresText = [
    state.features.eyeSize > 60 ? "large expressive eyes" : (state.features.eyeSize < 40 ? "slender elegant eyes" : "well-proportioned eyes"),
    state.features.lipThickness > 60 ? "full voluminous lips" : (state.features.lipThickness < 40 ? "thin refined lips" : "balanced lips"),
    state.features.noseWidth > 60 ? "broad nose" : (state.features.noseWidth < 40 ? "slim narrow nose" : "proportionate nose"),
    state.features.doubleEyelid ? "distinct double eyelids" : "clean monolid eye look",
    state.features.jawlineSharpness > 70 ? "very sharp defined jawline" : "soft natural jawline contour"
  ].join(", ");

  const skinText = `The skin should have a ${state.skin.tone} tone with ${state.skin.texture.join(" and ")} characteristics.`;
  const styleText = `Featuring a ${state.style.hairStyle} in a natural hue. The makeup style is ${state.style.makeupStyle}.`;

  // Explicitly instructing to keep background and match aspect ratio of original image
  const prompt = `Professional beauty transformation. 
    FACIAL MODIFICATIONS: ${featuresText}. 
    SKIN: ${skinText}. 
    STYLE: ${styleText}. 
    CRITICAL REQUIREMENT: Strictly maintain the EXACT original background from the base face image. Do not change, blur, or replace the background. 
    Keep the composition, lighting style, and environmental context identical to the provided base image.
    QUALITY: High-fidelity realistic skin, 2K resolution textures.`;

  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({
      inlineData: {
        data: baseData,
        mimeType: mimeType
      }
    });
  }

  if (state.referenceImage) {
    const refData = state.referenceImage.split(',')[1];
    const mimeType = state.referenceImage.split(';')[0].split(':')[1];
    parts.push({
      inlineData: {
        data: refData,
        mimeType: mimeType
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

