import { GoogleGenAI } from "@google/genai";
import { BeautyState } from "../types";
import { SKIN_TONES, SKIN_TEXTURES } from "../constants";

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, style, enabledFeatures, customPrompts, referenceImage } = state;

  // Face Feature Description
  let faceInstruction = "";
  if (enabledFeatures.face) {
    const eyeDesc = features.eyeSize > 70 ? "enlarged doe-eyed appearance" : 
                   (features.eyeSize < 30 ? "refined narrow aesthetic eyes" : "symmetrical eyes");
    const lipDesc = features.lipThickness > 70 ? "high-volume pouty lips" : 
                   (features.lipThickness < 30 ? "minimalist lip contour" : "balanced lips");
    const noseDesc = features.noseWidth < 30 ? "slim refined nasal base" : 
                    (features.noseWidth > 70 ? "natural wide structure" : "proportionate nose");
    const jawDesc = features.jawlineSharpness > 70 ? "chiseled v-line jawline" : "natural jawline";
    const eyeTilt = features.canthalTilt > 70 ? "positive canthal foxy-eye tilt" : 
                   (features.canthalTilt < 30 ? "soft puppy-eye tilt" : "neutral tilt");

    faceInstruction = `
    FACIAL ADJUSTMENTS:
    - Apply these structural changes: ${eyeDesc}, ${features.doubleEyelid ? 'prominent double eyelids' : 'monolids'}, ${eyeTilt}, ${lipDesc}, ${noseDesc}, ${jawDesc}.
    ${customPrompts.face ? `- Custom face request: ${customPrompts.face}` : ''}`;
  } else {
    faceInstruction = "\n- KEEP ORIGINAL FACIAL STRUCTURE UNCHANGED.";
  }

  // Skin Feature Description
  let skinInstruction = "";
  if (enabledFeatures.skin) {
    const tonePrompt = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const texturePrompts = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).filter(Boolean).join(", ");

    skinInstruction = `
    SKIN & TEXTURE:
    - Tone: ${tonePrompt}.
    - Features: ${texturePrompts}.
    ${customPrompts.skin ? `- Custom skin request: ${customPrompts.skin}` : ''}`;
  } else {
    skinInstruction = "\n- KEEP ORIGINAL SKIN TONE AND TEXTURE UNCHANGED.";
  }

  // Style Feature Description
  let styleInstruction = "";
  if (enabledFeatures.style) {
    styleInstruction = `
    STYLE & ARTISTRY:
    - Hairstyle: ${style.hairStyle}.
    - Makeup: ${style.makeupStyle} aesthetic.
    ${customPrompts.style ? `- Custom style request: ${customPrompts.style}` : ''}`;
  } else {
    styleInstruction = "\n- KEEP ORIGINAL HAIR AND MAKEUP UNCHANGED.";
  }

  let referenceClause = "";
  if (referenceImage) {
    referenceClause = `
    REFERENCE ANALYSIS:
    A reference style image has been provided. Analyze its aesthetic, makeup application, hair flow, and lighting style. 
    Synthesize the base image to match the reference's overall mood and stylistic cues while maintaining the identity of the person in the base image.`;
  }

  return `Act as an expert plastic surgeon and professional editorial retoucher. 
    TASK: Perform high-fidelity facial synthesis on the provided base image.

    GUIDELINES:
    1. IDENTITY PRESERVATION: Strictly maintain the bone structure and recognizable identity of the subject in the base image.
    2. BACKGROUND INTEGRITY: Do not alter the background or environment.
    ${referenceClause}

    SPECIFIC INSTRUCTIONS:
    ${faceInstruction}
    ${skinInstruction}
    ${styleInstruction}

    QUALITY: Produce 2K resolution, photorealistic editorial photography quality. Ensure seamless integration of all features.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);

  const parts: any[] = [{ text: prompt }];

  // Priority 1: Base Image (The Target)
  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  // Priority 2: Reference Image (The Style Source)
  if (state.referenceImage) {
    const refData = state.referenceImage.split(',')[1];
    const mimeType = state.referenceImage.split(';')[0].split(':')[1];
    parts.push({ inlineData: { data: refData, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import { GoogleGenAI } from "@google/genai";
import { BeautyState } from "../types";
import { SKIN_TONES, SKIN_TEXTURES } from "../constants";

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, style, enabledFeatures, customPrompts, referenceImage } = state;

  // Face Feature Description
  let faceInstruction = "";
  if (enabledFeatures.face) {
    const eyeDesc = features.eyeSize > 70 ? "enlarged doe-eyed appearance" : 
                   (features.eyeSize < 30 ? "refined narrow aesthetic eyes" : "symmetrical eyes");
    const lipDesc = features.lipThickness > 70 ? "high-volume pouty lips" : 
                   (features.lipThickness < 30 ? "minimalist lip contour" : "balanced lips");
    const noseDesc = features.noseWidth < 30 ? "slim refined nasal base" : 
                    (features.noseWidth > 70 ? "natural wide structure" : "proportionate nose");
    const jawDesc = features.jawlineSharpness > 70 ? "chiseled v-line jawline" : "natural jawline";
    const eyeTilt = features.canthalTilt > 70 ? "positive canthal foxy-eye tilt" : 
                   (features.canthalTilt < 30 ? "soft puppy-eye tilt" : "neutral tilt");

    faceInstruction = `
    FACIAL STRUCTURE (ENABLED):
    - Apply structural changes: ${eyeDesc}, ${features.doubleEyelid ? 'prominent double eyelids' : 'monolids'}, ${eyeTilt}, ${lipDesc}, ${noseDesc}, ${jawDesc}.
    ${customPrompts.face ? `- Additional User Request: ${customPrompts.face}` : ''}`;
  } else {
    faceInstruction = "\n- FACIAL STRUCTURE (DISABLED): STRICTLY MAINTAIN THE ORIGINAL FACE SHAPE AND FEATURES OF THE BASE IMAGE.";
  }

  // Skin Feature Description
  let skinInstruction = "";
  if (enabledFeatures.skin) {
    const tonePrompt = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const texturePrompts = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).filter(Boolean).join(", ");

    skinInstruction = `
    SKIN & COMPLEXION (ENABLED):
    - Tone: ${tonePrompt}.
    - Texture/Details: ${texturePrompts}.
    ${customPrompts.skin ? `- Additional User Request: ${customPrompts.skin}` : ''}`;
  } else {
    skinInstruction = "\n- SKIN & COMPLEXION (DISABLED): STRICTLY MAINTAIN THE ORIGINAL SKIN TONE AND TEXTURE OF THE BASE IMAGE.";
  }

  // Style Feature Description
  let styleInstruction = "";
  if (enabledFeatures.style) {
    styleInstruction = `
    HAIR & MAKEUP STYLE (ENABLED):
    - Hairstyle: ${style.hairStyle}.
    - Makeup Concept: ${style.makeupStyle} aesthetic.
    ${customPrompts.style ? `- Additional User Request: ${customPrompts.style}` : ''}`;
  } else {
    styleInstruction = "\n- HAIR & MAKEUP STYLE (DISABLED): STRICTLY MAINTAIN THE ORIGINAL HAIR AND MAKEUP OF THE BASE IMAGE.";
  }

  let referenceClause = "";
  if (referenceImage) {
    const referenceTargets = [];
    if (enabledFeatures.face) referenceTargets.push("facial structure and symmetry cues");
    if (enabledFeatures.skin) referenceTargets.push("skin tone, luminosity, and texture quality");
    if (enabledFeatures.style) referenceTargets.push("hair flow, volume, and makeup application details");

    referenceClause = `
    REFERENCE IMAGE UTILIZATION:
    A reference image is provided. ONLY analyze and apply the following aspects from the reference image: ${referenceTargets.join(', ')}.
    - IGNORE all other aspects of the reference image not listed above.
    - STRICT PROHIBITION: DO NOT adopt the clothing, outfit, accessories, jewelry, or background from the reference image. The subject must wear the exact same clothing as in the base image.`;
  }

  return `Act as a world-class aesthetic physician and high-end fashion retoucher. 
    TASK: Synthesize the provided base image with professional-grade beauty adjustments.

    CRITICAL CONSTRAINTS:
    1. IDENTITY: You MUST preserve the fundamental identity and likeness of the person in the base image.
    2. CLOTHING: STRICTLY RETAIN THE ORIGINAL CLOTHING AND ACCESSORIES from the base image. NEVER change the outfit.
    3. BACKGROUND: Keep the background of the base image exactly as it is.

    ${referenceClause}

    CATEGORICAL INSTRUCTIONS:
    ${faceInstruction}
    ${skinInstruction}
    ${styleInstruction}

    OUTPUT QUALITY: 2K Resolution (2048px), photorealistic, natural skin subsurface scattering, high-end editorial lighting finish.`;
};

