import React, { useState, useEffect, useMemo } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt } from './services/geminiService';
import { BeautyState, TabType } from './types';
import { INITIAL_FEATURES } from './constants';
import { Sparkles, Camera, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      style: null
    },
    features: INITIAL_FEATURES,
    skin: { tone: 'natural', texture: ['Smooth'] },
    style: { hairStyle: 'Long Wavy Silk', makeupStyle: 'Soft Glam' },
    customPrompts: {
      face: '',
      skin: '',
      style: ''
    },
    enabledFeatures: {
      face: true,
      skin: true,
      style: true
    },
    aspectRatio: '1:1'
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>(TabType.FEATURES);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_2K_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    updateState({ 
      baseImage: generatedImage,
      // Reset references when moving to next iteration if desired, 
      // but user asked for iterative editing so we keep the others.
    });
    setGeneratedImage(null);
    setIsComparing(false);
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const calculateAspectRatio = (img: HTMLImageElement): "1:1" | "3:4" | "4:3" | "9:16" | "16:9" => {
    const ratio = img.width / img.height;
    const options: { label: "1:1" | "3:4" | "4:3" | "9:16" | "16:9", value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'style') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = () => {
            const ratio = calculateAspectRatio(img);
            updateState({ baseImage: base64String, aspectRatio: ratio });
          };
          img.src = base64String;
        } else {
          updateState({ 
            referenceImages: { 
              ...state.referenceImages, 
              [type]: base64String 
            } 
          });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) {
    return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;
  }

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden text-zinc-100">
      <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/80 backdrop-blur-xl z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Sparkles className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight">BeautySynth <span className="text-indigo-500">PRO</span></h1>
            <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">Medical Grade Facial AI</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={handleGenerate}
            disabled={isGenerating || !state.baseImage}
            className={`flex items-center gap-2 px-8 py-2.5 rounded-full font-bold transition-all ${
              isGenerating || !state.baseImage
              ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed opacity-50' 
              : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-xl shadow-indigo-600/20'
            }`}
          >
            {isGenerating ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'Synthesizing (2K)...' : 'Generate Synthesis'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} activeTab={activeTab} setActiveTab={setActiveTab} onRefUpload={onFileUpload} />

        <div className="flex-1 p-6 flex flex-col gap-6 overflow-hidden bg-zinc-950">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-xl flex items-center justify-between text-sm shrink-0">
              <span>{error}</span>
              <button onClick={() => setError(null)}>✕</button>
            </div>
          )}

          <div className="flex flex-col flex-1 min-h-0 gap-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-0">
              {/* Base Image Section */}
              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative group shadow-inner">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Input: Base Image</h3>
                  {state.baseImage && (
                    <button onClick={() => updateState({ baseImage: null })} className="text-zinc-600 hover:text-red-400">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
                <div className="flex-1 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-zinc-900 to-black overflow-hidden">
                  {state.baseImage ? (
                    <img src={state.baseImage} className="max-w-full max-h-full object-contain" alt="Base" />
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-4">
                      <div className="w-20 h-20 rounded-full bg-zinc-800 flex items-center justify-center text-zinc-500 hover:text-indigo-400 transition-colors border border-zinc-700">
                        <Upload className="w-8 h-8" />
                      </div>
                      <span className="text-zinc-500 font-medium text-sm">Upload Base Image</span>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
              </div>

              {/* Output Section */}
              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative shadow-2xl">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Synthesis Result: 2K UHD</h3>
                  <div className="flex gap-2">
                    {generatedImage && (
                      <>
                        <button 
                          onClick={handleUseAsBase}
                          className="text-[10px] font-bold uppercase tracking-widest text-indigo-400 flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-500/10 border border-indigo-500/20 active:scale-95 transition-all hover:bg-indigo-500/20"
                          title="Use this result as the new base image for further editing"
                        >
                          <RefreshCcw className="w-3 h-3" />
                          Use as Base
                        </button>
                        <button 
                          onClick={handleDownload}
                          className="text-[10px] font-bold uppercase tracking-widest text-emerald-400 flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20 active:scale-95 transition-all hover:bg-emerald-500/20"
                        >
                          <Download className="w-3 h-3" />
                          Download
                        </button>
                        <button 
                          onMouseDown={() => setIsComparing(true)}
                          onMouseUp={() => setIsComparing(false)}
                          onMouseLeave={() => setIsComparing(false)}
                          className="text-[10px] font-bold uppercase tracking-widest text-zinc-400 flex items-center gap-2 px-3 py-1 rounded-full bg-zinc-500/10 border border-zinc-500/20 active:scale-95 select-none transition-all hover:bg-zinc-500/20"
                        >
                          {isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />}
                          Compare
                        </button>
                      </>
                    )}
                  </div>
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas 
                    image={isComparing ? state.baseImage : generatedImage} 
                    loading={isGenerating}
                    onDownload={handleDownload}
                  />
                  {isComparing && (
                    <div className="absolute top-4 left-4 px-3 py-1 bg-black/80 text-[10px] font-bold text-white uppercase tracking-widest rounded-full border border-white/20">
                      Original
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* Bottom Panel: Prompt Preview */}
            <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl p-4 flex flex-col gap-2 shrink-0 h-28 shadow-inner overflow-hidden">
              <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                <Zap className="w-3 h-3 text-indigo-500" /> Professional AI Prompt Preview
              </h3>
              <div className="flex-1 overflow-y-auto text-[11px] text-zinc-400 leading-relaxed font-mono bg-black/30 p-3 rounded-xl border border-zinc-800/50">
                {currentPrompt}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

