import { GoogleGenAI } from "@google/genai";
import { BeautyState } from "../types";
import { SKIN_TONES, SKIN_TEXTURES } from "../constants";

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, style, enabledFeatures, customPrompts, referenceImages } = state;

  // Face Feature Description
  let faceInstruction = "";
  if (enabledFeatures.face) {
    const eyeDesc = features.eyeSize > 70 ? "enlarged doe-eyed appearance" : 
                   (features.eyeSize < 30 ? "refined narrow aesthetic eyes" : "symmetrical eyes");
    const lipDesc = features.lipThickness > 70 ? "high-volume pouty lips" : 
                   (features.lipThickness < 30 ? "minimalist lip contour" : "balanced lips");
    const noseDesc = features.noseWidth < 30 ? "slim refined nasal base" : 
                    (features.noseWidth > 70 ? "natural wide structure" : "proportionate nose");
    const jawDesc = features.jawlineSharpness > 70 ? "chiseled v-line jawline" : "natural jawline";
    const eyeTilt = features.canthalTilt > 70 ? "positive canthal foxy-eye tilt" : 
                   (features.canthalTilt < 30 ? "soft puppy-eye tilt" : "neutral tilt");

    const refFacePart = referenceImages.face 
      ? "\n- REFERENCE USAGE (PRIMARY): Use the 'FACIAL_REFERENCE' image part as the ABSOLUTE guide for facial structure, symmetry, and features. Overlook manual settings below if they conflict with the image reference." 
      : `\n- MANUAL SETTINGS: Apply structural changes: ${eyeDesc}, ${features.doubleEyelid ? 'prominent double eyelids' : 'monolids'}, ${eyeTilt}, ${lipDesc}, ${noseDesc}, ${jawDesc}.`;

    faceInstruction = `
    FACIAL STRUCTURE (ENABLED):${refFacePart}
    ${customPrompts.face ? `- Additional User Request: ${customPrompts.face}` : ''}`;
  } else {
    faceInstruction = "\n- FACIAL STRUCTURE (DISABLED): STRICTLY MAINTAIN THE ORIGINAL FACE SHAPE AND FEATURES OF THE BASE IMAGE. Ignore any face-related references.";
  }

  // Skin Feature Description
  let skinInstruction = "";
  if (enabledFeatures.skin) {
    const tonePrompt = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const texturePrompts = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).filter(Boolean).join(", ");

    const refSkinPart = referenceImages.skin 
      ? "\n- REFERENCE USAGE (PRIMARY): Use the 'SKIN_REFERENCE' image part as the ABSOLUTE guide for skin tone, luminosity, and pore-level texture. Overlook manual settings below if they conflict." 
      : `\n- MANUAL SETTINGS: Tone: ${tonePrompt}. Texture/Details: ${texturePrompts}.`;

    skinInstruction = `
    SKIN & COMPLEXION (ENABLED):${refSkinPart}
    ${customPrompts.skin ? `- Additional User Request: ${customPrompts.skin}` : ''}`;
  } else {
    skinInstruction = "\n- SKIN & COMPLEXION (DISABLED): STRICTLY MAINTAIN THE ORIGINAL SKIN TONE AND TEXTURE OF THE BASE IMAGE. Ignore any skin-related references.";
  }

  // Style Feature Description
  let styleInstruction = "";
  if (enabledFeatures.style) {
    const refStylePart = referenceImages.style 
      ? "\n- REFERENCE USAGE (PRIMARY): Use the 'STYLE_REFERENCE' image part as the ABSOLUTE guide for hairstyle, volume, hair flow, and makeup details (eyeshadow, lip color, application style). Overlook manual settings below." 
      : `\n- MANUAL SETTINGS: Hairstyle: ${style.hairStyle}. Makeup Concept: ${style.makeupStyle} aesthetic.`;

    styleInstruction = `
    HAIR & MAKEUP STYLE (ENABLED):${refStylePart}
    ${customPrompts.style ? `- Additional User Request: ${customPrompts.style}` : ''}`;
  } else {
    styleInstruction = "\n- HAIR & MAKEUP STYLE (DISABLED): STRICTLY MAINTAIN THE ORIGINAL HAIR AND MAKEUP OF THE BASE IMAGE. Ignore any style-related references.";
  }

  return `Act as a world-class aesthetic physician and high-end fashion retoucher. 
    TASK: Synthesize the provided 'BASE_IMAGE' with professional-grade beauty adjustments.

    CRITICAL CONSTRAINTS:
    1. IDENTITY: You MUST preserve the fundamental identity and likeness of the person in the 'BASE_IMAGE'.
    2. CLOTHING & ACCESSORIES: STRICTLY RETAIN THE ORIGINAL CLOTHING, OUTFITS, JEWELRY, AND ACCESSORIES from the 'BASE_IMAGE'. NEVER adopt clothing from any reference images. This is a non-negotiable medical/artistic boundary.
    3. BACKGROUND: Keep the background of the 'BASE_IMAGE' exactly as it is.
    4. SELECTIVE REFERENCE: You are provided with several image parts. Only use the references for the categories that are explicitly ENABLED below. Each reference only applies to its specific category (e.g., STYLE_REFERENCE only for hair/makeup).

    CATEGORICAL INSTRUCTIONS:
    ${faceInstruction}
    ${skinInstruction}
    ${styleInstruction}

    OUTPUT QUALITY: 2K Resolution (2048px), photorealistic, natural skin subsurface scattering, high-end editorial lighting finish. Ensure seamless blending between the base person and the reference traits.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);

  const parts: any[] = [{ text: prompt }];

  // 1. Base Image (The Target)
  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: BASE_IMAGE" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  // 2. Face Reference (If enabled and present)
  if (state.enabledFeatures.face && state.referenceImages.face) {
    const data = state.referenceImages.face.split(',')[1];
    const mimeType = state.referenceImages.face.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: FACIAL_REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  // 3. Skin Reference (If enabled and present)
  if (state.enabledFeatures.skin && state.referenceImages.skin) {
    const data = state.referenceImages.skin.split(',')[1];
    const mimeType = state.referenceImages.skin.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: SKIN_REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  // 4. Style Reference (If enabled and present)
  if (state.enabledFeatures.style && state.referenceImages.style) {
    const data = state.referenceImages.style.split(',')[1];
    const mimeType = state.referenceImages.style.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: STYLE_REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

