                  state.enabledFeatures.face ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-600 bg-zinc-900'
                }`}
              >
                {state.enabledFeatures.face ? <ToggleRight className="w-3 h-3" /> : <ToggleLeft className="w-3 h-3" />}
                {state.enabledFeatures.face ? 'On' : 'Off'}
              </button>
            </div>
            <div className={`space-y-6 transition-opacity duration-300 ${state.enabledFeatures.face ? 'opacity-100' : 'opacity-30 pointer-events-none grayscale'}`}>
              <div className="relative space-y-6">
                <ReferenceLockOverlay category="face" />
                {[
                  { label: '눈 크기', key: 'eyeSize' },
                  { label: '눈꼬리 각도', key: 'canthalTilt' },
                  { label: '입술 두께', key: 'lipThickness' },
                  { label: '콧볼 너비', key: 'noseWidth' },
                  { label: '턱선 선명도', key: 'jawlineSharpness' },
                ].map(f => (
                  <div key={f.key} className="space-y-2">
                    <div className="flex justify-between text-[11px] font-bold">
                      <span className="text-zinc-500">{f.label}</span>
                      <span className="text-indigo-400">{(state.features as any)[f.key]}</span>
                    </div>
                    <input 
                      type="range" min="0" max="100" 
                      value={(state.features as any)[f.key]}
                      disabled={!!state.referenceImages.face}
                      onChange={(e) => handleFeatureChange(f.key, parseInt(e.target.value))}
                      className="w-full accent-indigo-600 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer disabled:cursor-not-allowed" 
                    />
                  </div>
                ))}
                <div className="flex items-center justify-between p-4 bg-zinc-900/30 border border-zinc-800/50 rounded-2xl">
