                    <div className={`absolute top-1 left-1 w-3 h-3 bg-white rounded-full transition-all ${state.features.doubleEyelid ? 'translate-x-5' : 'translate-x-0'}`} />
                  </button>
                </div>
              </div>
              <div className="space-y-3 pt-4 border-t border-zinc-900">
                <div className="flex items-center gap-2 text-zinc-500">
                  <MessageSquareText className="w-3 h-3" />
                  <span className="text-[10px] font-bold uppercase tracking-widest">추가 페이스 요청</span>
                </div>
                <textarea 
                  value={state.customPrompts.face}
                  onChange={(e) => handleCustomPromptChange('face', e.target.value)}
                  placeholder="예: 보조개 추가, 비대칭 교정 등..."
                  className="w-full h-24 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-xs text-zinc-300 outline-none focus:border-indigo-500 transition-all resize-none"
                />
              </div>
              {renderRefUploader('face', '페이스')}
            </div>
          </div>
        )}

        {activeTab === TabType.SKIN && (
          <div className="space-y-10">
            <div className="flex items-center justify-between text-zinc-500">
              <h4 className="text-[10px] font-bold uppercase tracking-widest">피부톤 및 질감</h4>
              <button 
                onClick={() => toggleFeature('skin')}
                className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[9px] font-bold transition-all uppercase tracking-widest ${
                  state.enabledFeatures.skin ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-600 bg-zinc-900'
                }`}
              >
                {state.enabledFeatures.skin ? <ToggleRight className="w-3 h-3" /> : <ToggleLeft className="w-3 h-3" />}
                {state.enabledFeatures.skin ? 'On' : 'Off'}
              </button>
            </div>
            <div className={`space-y-10 transition-opacity duration-300 ${state.enabledFeatures.skin ? 'opacity-100' : 'opacity-30 pointer-events-none grayscale'}`}>
              <div className="relative space-y-10">
                <ReferenceLockOverlay category="skin" />
                <div className="space-y-5">
                  <div className="flex flex-wrap gap-3">
                    {SKIN_TONES.map(tone => (
                      <button
                        key={tone.id}
                        disabled={!!state.referenceImages.skin}
                        onClick={() => updateState({ skin: { ...state.skin, tone: tone.id } })}
                        className={`relative w-10 h-10 rounded-full border-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed ${state.skin.tone === tone.id ? 'border-indigo-500 scale-110 shadow-xl' : 'border-zinc-800 hover:border-zinc-700'}`}
                        style={{ backgroundColor: tone.color }}
                        title={tone.label}
                      />
