                    {SKIN_TEXTURES.map(texture => (
                      <button
                        key={texture.id}
                        disabled={!!state.referenceImages.skin}
                        onClick={() => {
                          const newTextures = state.skin.texture.includes(texture.id)
                            ? state.skin.texture.filter(t => t !== texture.id)
                            : [...state.skin.texture, texture.id];
                          updateState({ skin: { ...state.skin, texture: newTextures } });
                        }}
                        className={`px-3 py-3 rounded-xl text-[10px] font-bold border transition-all disabled:opacity-50 disabled:cursor-not-allowed ${
                          state.skin.texture.includes(texture.id)
                          ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400 shadow-lg shadow-indigo-500/5'
                          : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:border-zinc-700'
