                className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[9px] font-bold transition-all uppercase tracking-widest ${
                  state.enabledFeatures.hair ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-600 bg-zinc-900'
                }`}
              >
                {state.enabledFeatures.hair ? <ToggleRight className="w-3 h-3" /> : <ToggleLeft className="w-3 h-3" />}
                {state.enabledFeatures.hair ? 'On' : 'Off'}
              </button>
            </div>
            <div className={`space-y-10 transition-opacity duration-300 ${state.enabledFeatures.hair ? 'opacity-100' : 'opacity-30 pointer-events-none grayscale'}`}>
              <div className="relative space-y-6">
                <ReferenceLockOverlay category="hair" />
                <div className="space-y-2">
                  {HAIR_STYLES.map(style => (
                    <button
                      key={style.id}
                      disabled={!!state.referenceImages.hair}
                      onClick={() => updateState({ hair: { ...state.hair, hairStyle: style.id } })}
                      className={`w-full px-4 py-3 text-left rounded-xl text-[11px] font-bold border transition-all disabled:opacity-50 disabled:cursor-not-allowed ${
                        state.hair.hairStyle === style.id
                        ? 'bg-indigo-600 border-indigo-500 text-white shadow-xl shadow-indigo-600/20'
                        : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:bg-zinc-900'
