                  disabled={!!state.referenceImages.makeup}
                  onChange={(e) => updateState({ makeup: { ...state.makeup, makeupStyle: e.target.value } })}
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 text-[11px] font-bold text-zinc-300 outline-none focus:border-indigo-500 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
