import React from 'react';
import { BeautyState, TabType } from '../types';
import { SKIN_TONES, SKIN_TEXTURES, HAIR_STYLES, MAKEUP_STYLES, MAKEUP_PRESETS } from '../constants';
import { User, Droplets, Scissors, Zap, Activity, ToggleLeft, ToggleRight, MessageSquareText, Upload, Trash2, Image as ImageIcon, Lock, Palette, Pipette } from 'lucide-react';

interface SidebarProps {
  state: BeautyState;
  updateState: (updates: Partial<BeautyState>) => void;
  activeTab: TabType;
  setActiveTab: (tab: TabType) => void;
  onRefUpload: (type: 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => void;
}

// Sub-components moved outside to ensure stable reference and prevent focus/dialog loss
const ReferenceLockOverlay = ({ category, referenceImages }: { category: 'face' | 'skin' | 'hair' | 'makeup', referenceImages: BeautyState['referenceImages'] }) => {
  if (!referenceImages[category]) return null;
  return (
    <div className="absolute inset-0 z-10 bg-zinc-950/40 backdrop-blur-[1px] flex items-center justify-center rounded-xl pointer-events-none">
      <div className="bg-black/80 px-3 py-1.5 rounded-full border border-zinc-800 flex items-center gap-2">
        <Lock className="w-3 h-3 text-indigo-400" />
        <span className="text-[9px] font-bold text-indigo-300 uppercase tracking-widest">Reference Active</span>
      </div>
    </div>
  );
};

const ColorSection = ({ 
  label, 
  field, 
  presets, 
  makeupState, 
  disabled, 
  onColorChange 
}: { 
  label: string, 
  field: 'eyeshadowColor' | 'lipstickColor' | 'blushColor', 
  presets: {color: string, label: string}[],
  makeupState: BeautyState['makeup'],
  disabled: boolean,
  onColorChange: (field: string, value: string) => void
}) => (
  <div className="space-y-3">
    <div className="flex justify-between items-center">
      <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">{label}</span>
      <div className="flex items-center gap-2">
        <span className="text-[9px] font-mono text-zinc-600 uppercase tracking-tighter">{makeupState[field]}</span>
        <label className="relative cursor-pointer group">
          <div className="w-5 h-5 rounded-md border border-zinc-700 overflow-hidden shadow-inner flex items-center justify-center transition-all group-hover:border-indigo-500">
            <div className="w-full h-full" style={{ backgroundColor: makeupState[field] }} />
            <Pipette className="w-2.5 h-2.5 text-white absolute mix-blend-difference opacity-0 group-hover:opacity-100 transition-opacity" />
          </div>
          <input 
            type="color" 
            className="absolute inset-0 opacity-0 cursor-pointer"
            value={makeupState[field]}
            disabled={disabled}
            // Use onInput for real-time visual feedback, though state updates will re-render
            onInput={(e) => onColorChange(field, (e.target as HTMLInputElement).value)}
            onChange={(e) => onColorChange(field, e.target.value)}
          />
        </label>
      </div>
    </div>
    <div className="flex flex-wrap gap-1.5 p-2 bg-black/20 rounded-xl border border-zinc-800/30">
      {presets.map((p, idx) => (
        <button
          key={idx}
          disabled={disabled}
          onClick={() => onColorChange(field, p.color)}
          className={`w-6 h-6 rounded-lg border-2 transition-all ${makeupState[field] === p.color ? 'border-indigo-500 scale-110 shadow-lg shadow-indigo-500/20' : 'border-transparent hover:border-zinc-700'}`}
          style={{ backgroundColor: p.color }}
          title={p.label}
        />
      ))}
    </div>
  </div>
);

export const StudioSidebar: React.FC<SidebarProps> = ({ state, updateState, activeTab, setActiveTab, onRefUpload }) => {
  const handleFeatureChange = (key: string, value: any) => {
    updateState({ features: { ...state.features, [key]: value } });
  };

  const handleMakeupChange = (key: string, value: any) => {
    updateState({ makeup: { ...state.makeup, [key]: value } });
  };

  const toggleFeature = (category: 'face' | 'skin' | 'hair' | 'makeup') => {
    updateState({
      enabledFeatures: {
        ...state.enabledFeatures,
        [category]: !state.enabledFeatures[category]
      }
    });
  };

  const handleCustomPromptChange = (category: keyof BeautyState['customPrompts'], value: string) => {
    updateState({
      customPrompts: {
        ...state.customPrompts,
        [category]: value
      }
    });
  };

  const removeReference = (category: 'face' | 'skin' | 'hair' | 'makeup') => {
    updateState({
      referenceImages: {
        ...state.referenceImages,
        [category]: null
      }
    });
  };

