import React, { useRef, useCallback } from 'react';
import { BeautyState, TabType } from '../types';
import { SKIN_TONES, SKIN_TEXTURES, HAIR_STYLES, MAKEUP_STYLES, MAKEUP_PRESETS } from '../constants';
import { User, Droplets, Scissors, Zap, Activity, ToggleLeft, ToggleRight, MessageSquareText, Upload, Trash2, Image as ImageIcon, Lock, Palette, Pipette } from 'lucide-react';

interface SidebarProps {
  state: BeautyState;
  updateState: (updates: Partial<BeautyState>) => void;
  activeTab: TabType;
  setActiveTab: (tab: TabType) => void;
  onRefUpload: (type: 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => void;
}

const ReferenceLockOverlay = React.memo(({ category, referenceImages }: { category: 'face' | 'skin' | 'hair' | 'makeup', referenceImages: BeautyState['referenceImages'] }) => {
  if (!referenceImages[category]) return null;
  return (
    <div className="absolute inset-0 z-10 bg-zinc-950/40 backdrop-blur-[1px] flex items-center justify-center rounded-xl pointer-events-none">
      <div className="bg-black/80 px-3 py-1.5 rounded-full border border-zinc-800 flex items-center gap-2">
        <Lock className="w-3 h-3 text-indigo-400" />
        <span className="text-[9px] font-bold text-indigo-300 uppercase tracking-widest">Reference Active</span>
      </div>
    </div>
  );
});

const ColorSection = React.memo(({ 
  label, 
  field, 
  presets, 
  colorValue, 
  disabled, 
  onColorChange 
}: { 
  label: string, 
  field: 'eyeshadowColor' | 'lipstickColor' | 'blushColor', 
  presets: {color: string, label: string}[],
  colorValue: string,
  disabled: boolean,
  onColorChange: (field: string, value: string) => void
}) => {
  const inputRef = useRef<HTMLInputElement>(null);

  const handlePickerClick = () => {
    if (!disabled && inputRef.current) {
      inputRef.current.click();
    }
  };

  return (
    <div className="space-y-3">
      <div className="flex justify-between items-center">
        <span className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest">{label}</span>
        <div className="flex items-center gap-2">
          <span className="text-[9px] font-mono text-zinc-600 uppercase tracking-tighter">{colorValue}</span>
          <div 
            onClick={handlePickerClick}
            className={`relative cursor-pointer group w-6 h-6 rounded-md border border-zinc-700 overflow-hidden shadow-inner flex items-center justify-center transition-all ${disabled ? 'opacity-50 grayscale cursor-not-allowed' : 'hover:border-indigo-500 hover:scale-105 active:scale-95'}`}
          >
            <div className="w-full h-full" style={{ backgroundColor: colorValue }} />
            <Pipette className="w-3 h-3 text-white absolute mix-blend-difference opacity-0 group-hover:opacity-100 transition-opacity" />
            <input 
              ref={inputRef}
              type="color" 
              className="absolute inset-0 opacity-0 pointer-events-none w-0 h-0"
              value={colorValue}
              disabled={disabled}
              onInput={(e) => onColorChange(field, (e.target as HTMLInputElement).value)}
              onChange={(e) => onColorChange(field, (e.target as HTMLInputElement).value)}
            />
          </div>
        </div>
      </div>
      <div className="flex flex-wrap gap-1.5 p-2 bg-black/20 rounded-xl border border-zinc-800/30">
        {presets.map((p, idx) => (
          <button
            key={idx}
            disabled={disabled}
            onClick={() => onColorChange(field, p.color)}
            className={`w-6 h-6 rounded-lg border-2 transition-all ${colorValue === p.color ? 'border-indigo-500 scale-110 shadow-lg shadow-indigo-500/20' : 'border-transparent hover:border-zinc-700'}`}
            style={{ backgroundColor: p.color }}
            title={p.label}
          />
        ))}
      </div>
    </div>
  );
});

export const StudioSidebar: React.FC<SidebarProps> = ({ state, updateState, activeTab, setActiveTab, onRefUpload }) => {
  const handleFeatureChange = useCallback((key: string, value: any) => {
    updateState({ features: { ...state.features, [key]: value } });
  }, [state.features, updateState]);

  const handleMakeupChange = useCallback((key: string, value: any) => {
    updateState({ makeup: { ...state.makeup, [key]: value } });
  }, [state.makeup, updateState]);

  const toggleFeature = useCallback((category: 'face' | 'skin' | 'hair' | 'makeup') => {
    updateState({
      enabledFeatures: {
        ...state.enabledFeatures,
        [category]: !state.enabledFeatures[category]
      }
    });
  }, [state.enabledFeatures, updateState]);

  const handleCustomPromptChange = useCallback((category: keyof BeautyState['customPrompts'], value: string) => {
    updateState({
      customPrompts: {
        ...state.customPrompts,
        [category]: value
      }
    });
  }, [state.customPrompts, updateState]);

  const removeReference = useCallback((category: 'face' | 'skin' | 'hair' | 'makeup') => {
    updateState({
      referenceImages: {
        ...state.referenceImages,
        [category]: null
      }
    });
  }, [state.referenceImages, updateState]);

  const renderRefUploader = (category: 'face' | 'skin' | 'hair' | 'makeup', label: string) => (
    <div className="space-y-3 pt-4 border-t border-zinc-900">
      <div className="flex items-center justify-between text-zinc-500">
        <div className="flex items-center gap-2">
          <ImageIcon className="w-3 h-3" />
          <span className="text-[10px] font-bold uppercase tracking-widest">{label} 레퍼런스</span>
        </div>
        {state.referenceImages[category] && (
          <button onClick={() => removeReference(category)} className="text-zinc-600 hover:text-red-400">
            <Trash2 className="w-3 h-3" />
          </button>
        )}
      </div>
      <div className="relative aspect-video bg-zinc-900/50 border border-dashed border-zinc-800 rounded-xl overflow-hidden flex items-center justify-center hover:bg-zinc-900 transition-colors group">
        {state.referenceImages[category] ? (
          <img 
            src={state.referenceImages[category]!} 
            className="w-full h-full object-contain" 
            alt="Reference" 
            style={{ imageRendering: 'auto' }}
          />
        ) : (
          <label className="cursor-pointer w-full h-full flex flex-col items-center justify-center gap-2">
            <Upload className="w-4 h-4 text-zinc-600 group-hover:text-indigo-400" />
            <span className="text-[9px] text-zinc-600 font-bold uppercase">이미지 업로드</span>
            <input type="file" className="hidden" accept="image/*" onChange={onRefUpload(category)} />
          </label>
        )}
      </div>
    </div>
  );

  return (
    <aside className="w-80 border-r border-zinc-900 bg-zinc-950 flex flex-col h-full z-20">
      <div className="flex border-b border-zinc-900">
        {[
          { id: TabType.FEATURES, icon: User, label: '페이스', category: 'face' as const },
          { id: TabType.SKIN, icon: Droplets, label: '피부', category: 'skin' as const },
          { id: TabType.HAIR, icon: Scissors, label: '헤어', category: 'hair' as const },
          { id: TabType.MAKEUP, icon: Palette, label: '메이크업', category: 'makeup' as const }
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex-1 py-5 flex flex-col items-center gap-1.5 transition-all relative ${
              activeTab === tab.id ? 'text-indigo-500 bg-zinc-900/50 shadow-inner border-b-2 border-indigo-500' : 'text-zinc-600 hover:text-zinc-400'
            }`}
          >
            <tab.icon className="w-4 h-4" />
            <span className="text-[9px] font-bold uppercase tracking-widest">{tab.label}</span>
            {!state.enabledFeatures[tab.category] && (
              <div className="absolute top-2 right-2 w-1.5 h-1.5 bg-zinc-700 rounded-full" />
            )}
            {state.referenceImages[tab.category] && (
              <div className="absolute top-2 left-2 w-1.5 h-1.5 bg-indigo-500 rounded-full animate-pulse" />
            )}
          </button>
        ))}
      </div>

      <div className="flex-1 overflow-y-auto p-7 space-y-10 custom-scrollbar">
        {activeTab === TabType.FEATURES && (
          <div className="space-y-8">
            <div className="flex items-center justify-between text-zinc-500">
              <div className="flex items-center gap-2">
                <Activity className="w-3 h-3" />
                <h4 className="text-[10px] font-bold uppercase tracking-widest">페이스 윤곽 및 디테일</h4>
              </div>
              <button 
                onClick={() => toggleFeature('face')}
                className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[9px] font-bold transition-all uppercase tracking-widest ${
                  state.enabledFeatures.face ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-600 bg-zinc-900'
                }`}
              >
                {state.enabledFeatures.face ? <ToggleRight className="w-3 h-3" /> : <ToggleLeft className="w-3 h-3" />}
                {state.enabledFeatures.face ? 'On' : 'Off'}
              </button>
            </div>
            <div className={`space-y-6 transition-opacity duration-300 ${state.enabledFeatures.face ? 'opacity-100' : 'opacity-30 pointer-events-none grayscale'}`}>
              <div className="relative space-y-6">
                <ReferenceLockOverlay category="face" referenceImages={state.referenceImages} />
                {[
                  { label: '눈 크기', key: 'eyeSize' },
                  { label: '눈꼬리 각도', key: 'canthalTilt' },
                  { label: '입술 두께', key: 'lipThickness' },
                  { label: '콧볼 너비', key: 'noseWidth' },
                  { label: '턱선 선명도', key: 'jawlineSharpness' },
                ].map(f => (
                  <div key={f.key} className="space-y-2">
                    <div className="flex justify-between text-[11px] font-bold">
                      <span className="text-zinc-500">{f.label}</span>
                      <span className="text-indigo-400">{(state.features as any)[f.key]}</span>
                    </div>
                    <input 
                      type="range" min="0" max="100" 
                      value={(state.features as any)[f.key]}
                      disabled={!!state.referenceImages.face}
                      onChange={(e) => handleFeatureChange(f.key, parseInt(e.target.value))}
                      className="w-full accent-indigo-600 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer disabled:cursor-not-allowed" 
                    />
                  </div>
                ))}
                <div className="flex items-center justify-between p-4 bg-zinc-900/30 border border-zinc-800/50 rounded-2xl">
                  <span className="text-[11px] font-bold text-zinc-400">쌍꺼풀</span>
                  <button 
                    disabled={!!state.referenceImages.face}
                    onClick={() => handleFeatureChange('doubleEyelid', !state.features.doubleEyelid)}
                    className={`w-10 h-5 rounded-full transition-all relative disabled:opacity-50 ${state.features.doubleEyelid ? 'bg-indigo-600 shadow-lg shadow-indigo-600/30' : 'bg-zinc-800'}`}
                  >
                    <div className={`absolute top-1 left-1 w-3 h-3 bg-white rounded-full transition-all ${state.features.doubleEyelid ? 'translate-x-5' : 'translate-x-0'}`} />
                  </button>
                </div>
              </div>
              <div className="space-y-3 pt-4 border-t border-zinc-900">
                <div className="flex items-center gap-2 text-zinc-500">
                  <MessageSquareText className="w-3 h-3" />
                  <span className="text-[10px] font-bold uppercase tracking-widest">추가 페이스 요청</span>
                </div>
                <textarea 
                  value={state.customPrompts.face}
                  onChange={(e) => handleCustomPromptChange('face', e.target.value)}
                  placeholder="예: 보조개 추가, 비대칭 교정 등..."
                  className="w-full h-24 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-xs text-zinc-300 outline-none focus:border-indigo-500 transition-all resize-none"
                />
              </div>
              {renderRefUploader('face', '페이스')}
            </div>
          </div>
        )}

        {activeTab === TabType.SKIN && (
          <div className="space-y-10">
            <div className="flex items-center justify-between text-zinc-500">
              <h4 className="text-[10px] font-bold uppercase tracking-widest">피부톤 및 질감</h4>
              <button 
                onClick={() => toggleFeature('skin')}
                className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[9px] font-bold transition-all uppercase tracking-widest ${
                  state.enabledFeatures.skin ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-600 bg-zinc-900'
                }`}
              >
                {state.enabledFeatures.skin ? <ToggleRight className="w-3 h-3" /> : <ToggleLeft className="w-3 h-3" />}
                {state.enabledFeatures.skin ? 'On' : 'Off'}
              </button>
            </div>
            <div className={`space-y-10 transition-opacity duration-300 ${state.enabledFeatures.skin ? 'opacity-100' : 'opacity-30 pointer-events-none grayscale'}`}>
              <div className="relative space-y-10">
                <ReferenceLockOverlay category="skin" referenceImages={state.referenceImages} />
                <div className="space-y-5">
                  <div className="flex flex-wrap gap-3">
                    {SKIN_TONES.map(tone => (
                      <button
                        key={tone.id}
                        disabled={!!state.referenceImages.skin}
                        onClick={() => updateState({ skin: { ...state.skin, tone: tone.id } })}
                        className={`relative w-10 h-10 rounded-full border-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed ${state.skin.tone === tone.id ? 'border-indigo-500 scale-110 shadow-xl' : 'border-zinc-800 hover:border-zinc-700'}`}
                        style={{ backgroundColor: tone.color }}
                        title={tone.label}
                      />
                    ))}
                  </div>
                </div>
                <div className="space-y-5">
                  <div className="grid grid-cols-2 gap-2">
                    {SKIN_TEXTURES.map(texture => (
                      <button
                        key={texture.id}
                        disabled={!!state.referenceImages.skin}
                        onClick={() => {
                          const newTextures = state.skin.texture.includes(texture.id)
                            ? state.skin.texture.filter(t => t !== texture.id)
                            : [...state.skin.texture, texture.id];
                          updateState({ skin: { ...state.skin, texture: newTextures } });
                        }}
                        className={`px-3 py-3 rounded-xl text-[10px] font-bold border transition-all disabled:opacity-50 disabled:cursor-not-allowed ${
                          state.skin.texture.includes(texture.id)
                          ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400 shadow-lg shadow-indigo-500/5'
                          : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:border-zinc-700'
                        }`}
                      >
                        {texture.label}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
              <div className="space-y-3 pt-4 border-t border-zinc-900">
                <div className="flex items-center gap-2 text-zinc-500">
                  <MessageSquareText className="w-3 h-3" />
                  <span className="text-[10px] font-bold uppercase tracking-widest">추가 피부 요청</span>
                </div>
                <textarea 
                  value={state.customPrompts.skin}
                  onChange={(e) => handleCustomPromptChange('skin', e.target.value)}
                  placeholder="예: 특정 부위 흉터 제거..."
                  className="w-full h-24 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-xs text-zinc-300 outline-none focus:border-indigo-500 transition-all resize-none"
                />
              </div>
              {renderRefUploader('skin', '피부')}
            </div>
          </div>
        )}

        {activeTab === TabType.HAIR && (
          <div className="space-y-10">
            <div className="flex items-center justify-between text-zinc-500">
              <h4 className="text-[10px] font-bold uppercase tracking-widest">헤어스타일 설정</h4>
              <button 
                onClick={() => toggleFeature('hair')}
                className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[9px] font-bold transition-all uppercase tracking-widest ${
                  state.enabledFeatures.hair ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-600 bg-zinc-900'
                }`}
              >
                {state.enabledFeatures.hair ? <ToggleRight className="w-3 h-3" /> : <ToggleLeft className="w-3 h-3" />}
                {state.enabledFeatures.hair ? 'On' : 'Off'}
              </button>
            </div>
            <div className={`space-y-10 transition-opacity duration-300 ${state.enabledFeatures.hair ? 'opacity-100' : 'opacity-30 pointer-events-none grayscale'}`}>
              <div className="relative space-y-6">
                <ReferenceLockOverlay category="hair" referenceImages={state.referenceImages} />
                <div className="space-y-2">
                  {HAIR_STYLES.map(style => (
                    <button
                      key={style.id}
                      disabled={!!state.referenceImages.hair}
                      onClick={() => updateState({ hair: { ...state.hair, hairStyle: style.id } })}
                      className={`w-full px-4 py-3 text-left rounded-xl text-[11px] font-bold border transition-all disabled:opacity-50 disabled:cursor-not-allowed ${
                        state.hair.hairStyle === style.id
                        ? 'bg-indigo-600 border-indigo-500 text-white shadow-xl shadow-indigo-600/20'
                        : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:bg-zinc-900'
                      }`}
                    >
                      {style.label}
                    </button>
                  ))}
                </div>
              </div>
              <div className="space-y-3 pt-4 border-t border-zinc-900">
                <div className="flex items-center gap-2 text-zinc-500">
                  <MessageSquareText className="w-3 h-3" />
                  <span className="text-[10px] font-bold uppercase tracking-widest">추가 헤어 요청</span>
                </div>
                <textarea 
                  value={state.customPrompts.hair}
                  onChange={(e) => handleCustomPromptChange('hair', e.target.value)}
                  placeholder="예: 핑크색 옴브레 헤어..."
                  className="w-full h-24 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-xs text-zinc-300 outline-none focus:border-indigo-500 transition-all resize-none"
                />
              </div>
              {renderRefUploader('hair', '헤어')}
            </div>
          </div>
        )}

        {activeTab === TabType.MAKEUP && (
          <div className="space-y-10">
            <div className="flex items-center justify-between text-zinc-500">
              <h4 className="text-[10px] font-bold uppercase tracking-widest">메이크업 설정</h4>
              <button 
                onClick={() => toggleFeature('makeup')}
                className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-[9px] font-bold transition-all uppercase tracking-widest ${
                  state.enabledFeatures.makeup ? 'text-indigo-400 bg-indigo-500/10' : 'text-zinc-600 bg-zinc-900'
                }`}
              >
                {state.enabledFeatures.makeup ? <ToggleRight className="w-3 h-3" /> : <ToggleLeft className="w-3 h-3" />}
                {state.enabledFeatures.makeup ? 'On' : 'Off'}
              </button>
            </div>
            <div className={`space-y-8 transition-opacity duration-300 ${state.enabledFeatures.makeup ? 'opacity-100' : 'opacity-30 pointer-events-none grayscale'}`}>
              <div className="relative space-y-6">
                <ReferenceLockOverlay category="makeup" referenceImages={state.referenceImages} />

                <div className="space-y-3">
                  <h5 className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-1.5">
                    <Zap className="w-3 h-3" /> 기본 컨셉
                  </h5>
                  <select 
                    value={state.makeup.makeupStyle}
                    disabled={!!state.referenceImages.makeup}
                    onChange={(e) => handleMakeupChange('makeupStyle', e.target.value)}
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 text-[11px] font-bold text-zinc-300 outline-none focus:border-indigo-500 transition-all disabled:opacity-50"
                  >
                    {MAKEUP_STYLES.map(style => (
                      <option key={style.id} value={style.id}>{style.label}</option>
                    ))}
                  </select>
                </div>

                <div className="space-y-8 p-5 bg-zinc-900/30 rounded-2xl border border-zinc-800/50 shadow-inner">
                  <h5 className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest border-b border-zinc-800 pb-3">세부 컬러 팔레트</h5>

                  <ColorSection 
                    label="아이섀도우" 
                    field="eyeshadowColor" 
                    presets={MAKEUP_PRESETS.eyeshadow} 
                    colorValue={state.makeup.eyeshadowColor}
                    disabled={!!state.referenceImages.makeup}
                    onColorChange={handleMakeupChange}
                  />

                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold">
                      <span className="text-zinc-500">아이라이너 강도</span>
                      <span className="text-indigo-400">{state.makeup.eyelinerIntensity}%</span>
                    </div>
                    <input 
                      type="range" min="0" max="100" 
                      value={state.makeup.eyelinerIntensity}
                      disabled={!!state.referenceImages.makeup}
                      onChange={(e) => handleMakeupChange('eyelinerIntensity', parseInt(e.target.value))}
                      className="w-full accent-indigo-600 h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer" 
                    />
                  </div>

                  <ColorSection 
                    label="립스틱 컬러" 
                    field="lipstickColor" 
                    presets={MAKEUP_PRESETS.lipstick} 
                    colorValue={state.makeup.lipstickColor}
                    disabled={!!state.referenceImages.makeup}
                    onColorChange={handleMakeupChange}
                  />

                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold">
                      <span className="text-zinc-500">립 글로스/광택</span>
                      <span className="text-indigo-400">{state.makeup.lipstickGloss}%</span>
                    </div>
                    <input 
                      type="range" min="0" max="100" 
                      value={state.makeup.lipstickGloss}
                      disabled={!!state.referenceImages.makeup}
                      onChange={(e) => handleMakeupChange('lipstickGloss', parseInt(e.target.value))}
                      className="w-full accent-indigo-600 h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer" 
                    />
                  </div>

                  <ColorSection 
                    label="치크/블러셔" 
                    field="blushColor" 
                    presets={MAKEUP_PRESETS.blush} 
                    colorValue={state.makeup.blushColor}
                    disabled={!!state.referenceImages.makeup}
                    onColorChange={handleMakeupChange}
                  />

                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold">
                      <span className="text-zinc-500">블러셔 선명도</span>
                      <span className="text-indigo-400">{state.makeup.blushIntensity}%</span>
                    </div>
                    <input 
                      type="range" min="0" max="100" 
                      value={state.makeup.blushIntensity}
                      disabled={!!state.referenceImages.makeup}
                      onChange={(e) => handleMakeupChange('blushIntensity', parseInt(e.target.value))}
                      className="w-full accent-indigo-600 h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer" 
                    />
                  </div>
                </div>
              </div>

              <div className="space-y-3 pt-4 border-t border-zinc-900">
                <div className="flex items-center gap-2 text-zinc-500">
                  <MessageSquareText className="w-3 h-3" />
                  <span className="text-[10px] font-bold uppercase tracking-widest">추가 메이크업 요청</span>
                </div>
                <textarea 
                  value={state.customPrompts.makeup}
                  onChange={(e) => handleCustomPromptChange('makeup', e.target.value)}
                  placeholder="예: 화려한 보석 메이크업..."
                  className="w-full h-24 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-xs text-zinc-300 outline-none focus:border-indigo-500 transition-all resize-none"
                />
              </div>
              {renderRefUploader('makeup', '메이크업')}
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-zinc-950 border-t border-zinc-900 shrink-0">
        <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-500/20">
          <div className="flex items-center gap-2 mb-2 text-indigo-400">
            <Zap className="w-3 h-3 fill-current" />
            <span className="text-[9px] font-bold uppercase tracking-widest">뉴럴 엔진 3.0</span>
          </div>
          <p className="text-[10px] text-zinc-500 leading-relaxed font-medium">
            컬러 피커를 통해 세상에 없는 나만의 컬러를 조합해 보세요.
          </p>
        </div>
      </div>
    </aside>
  );
};

export interface FacialFeatures {
  eyeSize: number;
  lipThickness: number;
  noseWidth: number;
  doubleEyelid: boolean;
  jawlineSharpness: number;
  canthalTilt: number;
}

export interface SkinFeatures {
  tone: string;
  texture: string[];
}

export interface HairFeatures {
  hairStyle: string;
  hairColor: string;
}

export interface MakeupFeatures {
  makeupStyle: string;
  eyeshadowColor: string;
  eyelinerIntensity: number;
  lipstickColor: string;
  lipstickGloss: number;
  blushColor: string;
  blushIntensity: number;
}

export interface BeautyState {
  baseImage: string | null;
  referenceImages: {
    face: string | null;
    skin: string | null;
    hair: string | null;
    makeup: string | null;
  };
  features: FacialFeatures;
  skin: SkinFeatures;
  hair: HairFeatures;
  makeup: MakeupFeatures;
  customPrompts: {
    face: string;
    skin: string;
    hair: string;
    makeup: string;
  };
  enabledFeatures: {
    face: boolean;
    skin: boolean;
    hair: boolean;
    makeup: boolean;
  };
  aspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

export enum TabType {
  FEATURES = 'FEATURES',
  SKIN = 'SKIN',
  HAIR = 'HAIR',
  MAKEUP = 'MAKEUP'
}

/**
 * Augmenting the global Window interface to include aistudio.
 */
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}

