import { GoogleGenAI } from "@google/genai";
import { BeautyState } from "../types";
import { SKIN_TONES, SKIN_TEXTURES } from "../constants";

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, enabledFeatures, customPrompts, referenceImages } = state;

  // Face Feature Description
  let faceInstruction = "";
  if (enabledFeatures.face) {
    const eyeDesc = features.eyeSize > 70 ? "enlarged doe-eyed appearance" : 
                   (features.eyeSize < 30 ? "refined narrow aesthetic eyes" : "symmetrical eyes");
    const lipDesc = features.lipThickness > 70 ? "high-volume pouty lips" : 
                   (features.lipThickness < 30 ? "minimalist lip contour" : "balanced lips");
    const noseDesc = features.noseWidth < 30 ? "slim refined nasal base" : 
                    (features.noseWidth > 70 ? "natural wide structure" : "proportionate nose");
    const jawDesc = features.jawlineSharpness > 70 ? "chiseled v-line jawline" : "natural jawline";
    const eyeTilt = features.canthalTilt > 70 ? "positive canthal foxy-eye tilt" : 
                   (features.canthalTilt < 30 ? "soft puppy-eye tilt" : "neutral tilt");

    const refFacePart = referenceImages.face 
      ? "\n- REFERENCE USAGE (PRIMARY): Use 'FACIAL_REFERENCE' to guide structural changes and facial traits. Overlook manual settings below if conflict." 
      : `\n- MANUAL SETTINGS: Structural changes: ${eyeDesc}, ${features.doubleEyelid ? 'prominent double eyelids' : 'monolids'}, ${eyeTilt}, ${lipDesc}, ${noseDesc}, ${jawDesc}.`;

    faceInstruction = `
    FACIAL STRUCTURE (ENABLED):${refFacePart}
    ${customPrompts.face ? `- Additional User Request: ${customPrompts.face}` : ''}`;
  } else {
    faceInstruction = "\n- FACIAL STRUCTURE (DISABLED): MAINTAIN ORIGINAL FACE SHAPE.";
  }

  // Skin Feature Description
  let skinInstruction = "";
  if (enabledFeatures.skin) {
    const tonePrompt = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const texturePrompts = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).filter(Boolean).join(", ");
    const refSkinPart = referenceImages.skin 
      ? "\n- REFERENCE USAGE (PRIMARY): Use 'SKIN_REFERENCE' for tone, luminosity, and pore-level texture." 
      : `\n- MANUAL SETTINGS: Tone: ${tonePrompt}. Texture: ${texturePrompts}.`;

    skinInstruction = `
    SKIN & COMPLEXION (ENABLED):${refSkinPart}
    ${customPrompts.skin ? `- Additional User Request: ${customPrompts.skin}` : ''}`;
  } else {
    skinInstruction = "\n- SKIN & COMPLEXION (DISABLED): MAINTAIN ORIGINAL SKIN.";
  }

  // Hair Feature Description
  let hairInstruction = "";
  if (enabledFeatures.hair) {
    const hairColorDesc = `precise hair color hex ${hair.hairColor}`;
    const refHairPart = referenceImages.hair 
      ? `\n- REFERENCE USAGE (PRIMARY): Use 'HAIR_REFERENCE' for hairstyle volume and flow. COLOR MUST strictly follow: ${hairColorDesc}.` 
      : `\n- MANUAL SETTINGS: Hairstyle: ${hair.hairStyle}. Color: ${hairColorDesc}.`;

    hairInstruction = `
    HAIRSTYLE (ENABLED):${refHairPart}
    ${customPrompts.hair ? `- Additional User Request: ${customPrompts.hair}` : ''}`;
  } else {
    hairInstruction = "\n- HAIRSTYLE (DISABLED): MAINTAIN ORIGINAL HAIR.";
  }

  // Makeup Feature Description
  let makeupInstruction = "";
  if (enabledFeatures.makeup) {
    const detailedArtistry = `
    - Eyes: Precise eyeshadow color hex ${makeup.eyeshadowColor}, intensity ${makeup.eyelinerIntensity}% professional eyeliner.
    - Lips: Precise lipstick color hex ${makeup.lipstickColor}, ${makeup.lipstickGloss}% gloss/shine intensity.
    - Cheeks: Precise blush color hex ${makeup.blushColor}, intensity ${makeup.blushIntensity}%.`;

    const refMakeupPart = referenceImages.makeup 
      ? "\n- REFERENCE USAGE (PRIMARY): Use 'MAKEUP_REFERENCE' ABSOLUTELY ONLY for makeup colors, eyeshadow application, eyeliner style, lip shade, and blush. IGNORE the hairstyle or person in this image." 
      : `\n- MANUAL SETTINGS: Concept: ${makeup.makeupStyle}.${detailedArtistry}`;

    makeupInstruction = `
    MAKEUP (ENABLED):${refMakeupPart}
    ${customPrompts.makeup ? `- Additional User Request: ${customPrompts.makeup}` : ''}`;
  } else {
    makeupInstruction = "\n- MAKEUP (DISABLED): MAINTAIN ORIGINAL MAKEUP.";
  }

  return `Act as a world-class aesthetic physician and high-end fashion retoucher. 
    TASK: Synthesize the provided 'BASE_IMAGE' with professional-grade beauty adjustments.

    CRITICAL CONSTRAINTS:
    1. IDENTITY: You MUST preserve the fundamental identity and likeness of the person in the 'BASE_IMAGE'.
    2. CLOTHING & ACCESSORIES: STRICTLY RETAIN THE ORIGINAL CLOTHING, OUTFITS, JEWELRY, AND ACCESSORIES from the 'BASE_IMAGE'. NEVER adopt clothing from any reference images.
    3. BACKGROUND: Keep the background of the 'BASE_IMAGE' exactly as it is.
    4. SELECTIVE REFERENCE: You are provided with several image parts. Use HAIR_REFERENCE ONLY for hair volume/shape. Use MAKEUP_REFERENCE ONLY for colors/cosmetic application.

    CATEGORICAL INSTRUCTIONS:
    ${faceInstruction}
    ${skinInstruction}
    ${hairInstruction}
    ${makeupInstruction}

    OUTPUT: 2K Resolution, photorealistic editorial finish. Ensure seamless blending and realistic skin-light interaction with hair and makeup colors.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);

  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: BASE_IMAGE" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.enabledFeatures.face && state.referenceImages.face) {
    const data = state.referenceImages.face.split(',')[1];
    const mimeType = state.referenceImages.face.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: FACIAL_REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.enabledFeatures.skin && state.referenceImages.skin) {
    const data = state.referenceImages.skin.split(',')[1];
    const mimeType = state.referenceImages.skin.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: SKIN_REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.enabledFeatures.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: HAIR_REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.enabledFeatures.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "IMAGE_PART: MAKEUP_REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

