const getSliderAdjective = (value: number, type: 'eyes' | 'lips' | 'nose' | 'jaw' | 'tilt'): string => {
  if (value >= 80) {
    switch (type) {
      case 'eyes': return "large doll-like eyes";
      case 'lips': return "plump voluminous lips";
      case 'nose': return "broad natural nose structure";
      case 'jaw': return "razor-sharp chiseled V-line jaw";
      case 'tilt': return "dramatic upturned foxy-eye tilt";
    }
  }
  if (value <= 20) {
    switch (type) {
      case 'eyes': return "refined narrow eyes";
      case 'lips': return "thin elegant minimalist lips";
      case 'nose': return "slim sharp nasal base";
      case 'jaw': return "soft rounded jawline";
      case 'tilt': return "gentle downturned puppy-eye tilt";
    }
  }
  return `natural proportionate ${type === 'tilt' ? 'eye tilt' : type}`;
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, enabledFeatures, customPrompts, referenceImages } = state;

  // 1. Morphing: Mapping slider values to adjectives
  const faceParts = [];
  if (enabledFeatures.face) {
    faceParts.push(getSliderAdjective(features.eyeSize, 'eyes'));
    faceParts.push(getSliderAdjective(features.lipThickness, 'lips'));
    faceParts.push(getSliderAdjective(features.noseWidth, 'nose'));
    faceParts.push(getSliderAdjective(features.jawlineSharpness, 'jaw'));
    faceParts.push(getSliderAdjective(features.canthalTilt, 'tilt'));
    if (features.doubleEyelid) faceParts.push("prominent double eyelids");
  }

  // 2. Specific Phrasing for Hex Colors & Reference Priority
  let hairText = "";
  if (enabledFeatures.hair) {
    const colorDesc = `hair dyed in ${hair.hairColor} color`;
    const refText = referenceImages.hair 
      ? "Strictly follow the HAIRSTYLE from Reference Image 1." 
      : `Hairstyle: ${hair.hairStyle}.`;
    hairText = `HAIR: ${refText} Ensure the hair is ${colorDesc}. ${customPrompts.hair}`;
  }

  let makeupText = "";
  if (enabledFeatures.makeup) {
    const colorDesc = `lips painted in ${makeup.lipColor} color, eyeshadow applied in ${makeup.eyeshadowColor} color, and blush applied in ${makeup.blushColor} color.`;
    const refText = referenceImages.makeup 
      ? "Strictly follow the MAKEUP STYLE from Reference Image 2." 
      : `Makeup Concept: ${makeup.makeupStyle}.`;
    makeupText = `MAKEUP: ${refText} Specific details: ${colorDesc} Eyeliner intensity ${makeup.eyelinerIntensity}%, Lipstick gloss ${makeup.lipstickGloss}%. ${customPrompts.makeup}`;
  }

  let skinText = "";
  if (enabledFeatures.skin) {
    const tone = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const textures = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ");
    skinText = `SKIN: ${tone} with ${textures}. ${customPrompts.skin}`;
  }

  return `Act as a world-class aesthetic physician and high-end fashion retoucher.
    TASK: Synthesize the provided 'Base Image' with professional-grade beauty adjustments.

    IDENTITY PRESERVATION: You MUST preserve the fundamental identity and likeness of the person in the 'Base Image'. Keep the original clothing, background, and accessories.

    CORE INSTRUCTIONS:
    - FACIAL STRUCTURE: ${enabledFeatures.face ? `Adjust to have ${faceParts.join(", ")}. ${customPrompts.face}` : "Maintain original facial structure."}
    - ${hairText}
    - ${makeupText}
    - ${skinText}

    IMAGE PARTS GUIDE:
    - Base Image: The target person.
    - Reference Image 1: The hairstyle source.
    - Reference Image 2: The makeup style source.

    OUTPUT: 2K Resolution, photorealistic editorial finish. Ensure seamless blending of the specified hex colors and professional textures.`;
};

