import { GoogleGenAI } from "@google/genai";
import { BeautyState } from "../types";
import { SKIN_TONES, SKIN_TEXTURES } from "../constants";

const getSliderAdjective = (value: number, type: string): string => {
  if (value >= 80) {
    switch (type) {
      case 'eyeSize': return "large doll-like eyes";
      case 'lipThickness': return "plump voluminous lips";
      case 'noseWidth': return "natural wide nose structure";
      case 'jawlineSharpness': return "razor-sharp chiseled jawline";
      case 'canthalTilt': return "fierce cat-eyes with upturned corners";
      case 'jawShape': return "ultra-defined sharp chin and jaw";
      case 'cheekboneHeight': return "high prominent cheekbones";
      case 'faceWidth': return "broad rounded facial structure";
      case 'eyeDistance': return "wide-set expressive eyes";
      case 'noseBridge': return "high-defined aquiline nasal bridge";
      case 'mouthCorners': return "cheerful upturned mouth corners";
      case 'lipCupidBow': return "sharply defined M-shaped cupid's bow";
      case 'skinAge': return "mature skin with distinguished character";
      case 'glowIntensity': return "high-shine dewy glass-skin finish";
      case 'blemishIntensity': return "distinctive natural skin texture and freckles";
    }
  }
  if (value <= 20) {
    switch (type) {
      case 'eyeSize': return "refined narrow aesthetic eyes";
      case 'lipThickness': return "elegant thin minimalist lips";
      case 'noseWidth': return "ultra-slim refined nasal base";
      case 'jawlineSharpness': return "soft youthful jawline contour";
      case 'canthalTilt': return "gentle downturned puppy-eye look";
      case 'jawShape': return "soft round organic face shape";
      case 'cheekboneHeight': return "soft sunken model-like cheeks";
      case 'faceWidth': return "ultra-slim V-line facial contour";
      case 'eyeDistance': return "close-set focused eyes";
      case 'noseBridge': return "soft flat elegant nose bridge";
      case 'mouthCorners': return "moody slightly downturned mouth corners";
      case 'lipCupidBow': return "softly blurred round lip contour";
      case 'skinAge': return "youthful baby-smooth porcelain skin";
      case 'glowIntensity': return "sophisticated ultra-matte powdery finish";
      case 'blemishIntensity': return "completely flawless airbrushed skin";
    }
  }
  return `natural ${type}`;
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, enabledFeatures, customPrompts, referenceImages } = state;

  // 1. Morphing: Mapping all granular sliders
  const faceParts = [];
  if (enabledFeatures.face) {
    Object.keys(features).forEach(key => {
      if (typeof (features as any)[key] === 'number') {
        faceParts.push(getSliderAdjective((features as any)[key], key));
      }
    });
    faceParts.push(`${features.eyelidType} eyelids`);
  }

  // 2. Skin Logic
  let skinText = "";
  if (enabledFeatures.skin) {
    const tone = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const textures = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ");
    skinText = `SKIN: ${tone} with ${textures}. Glow: ${getSliderAdjective(skin.glowIntensity, 'glowIntensity')}, Age: ${getSliderAdjective(skin.skinAge, 'skinAge')}, Texture: ${getSliderAdjective(skin.blemishIntensity, 'blemishIntensity')}. ${customPrompts.skin}`;
  }

  // 3. Hair Logic (Ombre)
  let hairText = "";
  if (enabledFeatures.hair) {
    const colorDesc = `hair with an ombre effect transitioning from roots in ${hair.hairRootColor} color to the main length in ${hair.hairColor} color`;
    const refText = referenceImages.hair 
      ? "Strictly follow the HAIRSTYLE from Reference Image 1." 
      : `Hairstyle: ${hair.hairStyle}.`;
    hairText = `HAIR: ${refText} Ensure the hair is dyed in ${colorDesc}. ${customPrompts.hair}`;
  }

  // 4. Makeup Logic
  let makeupText = "";
  if (enabledFeatures.makeup) {
    const colorDesc = `lips painted in ${makeup.lipColor} color, eyeshadow applied in ${makeup.eyeshadowColor} color, and blush applied in ${makeup.blushColor} color.`;
    const refText = referenceImages.makeup 
      ? "Strictly follow the MAKEUP STYLE from Reference Image 2." 
      : `Makeup Concept: ${makeup.makeupStyle}.`;
    makeupText = `MAKEUP: ${refText} Specific details: ${colorDesc} Eyeliner intensity ${makeup.eyelinerIntensity}%, Lipstick gloss ${makeup.lipstickGloss}%. ${customPrompts.makeup}`;
  }

  return `Act as a world-class character designer and high-end aesthetic retoucher.
    TASK: Synthesize the provided 'Base Image' with professional character creation level customization.

    IDENTITY PRESERVATION: You MUST preserve the fundamental identity of the person in the 'Base Image'. Keep the original clothing and background.

    CHARACTER PARAMETERS:
    - FACIAL SCULPTING: ${enabledFeatures.face ? `Sculpt features to have: ${faceParts.join(", ")}. ${customPrompts.face}` : "Maintain original facial structure."}
    - ${hairText}
    - ${makeupText}
    - ${skinText}

    IMAGE PARTS GUIDE:
    - Base Image: The target identity.
    - Reference Image 1: Primary source for hairstyle volume and silhouette.
    - Reference Image 2: Primary source for makeup application style.

    OUTPUT: 2K Resolution, ultra-realistic editorial finish. Ensure perfect blending of the specified hex colors and professional lighting interaction.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);

  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "Base Image" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.enabledFeatures.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "Reference Image 1" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.enabledFeatures.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "Reference Image 2" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

