export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, enabledFeatures, customPrompts, referenceImages } = state;

  // 1. Facial Sculpting Logic
  const faceParts = [];
  if (enabledFeatures.face) {
    Object.keys(features).forEach(key => {
      if (typeof (features as any)[key] === 'number') {
        faceParts.push(getSliderAdjective((features as any)[key], key));
      }
    });
    faceParts.push(`${features.eyelidType} eyelids`);
  }

  // 2. Skin Logic
  let skinText = "";
  if (enabledFeatures.skin) {
    const tone = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const textures = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ");
    skinText = `SKIN: ${tone} with ${textures}. Glow: ${getSliderAdjective(skin.glowIntensity, 'glowIntensity')}, Age: ${getSliderAdjective(skin.skinAge, 'skinAge')}, Texture: ${getSliderAdjective(skin.blemishIntensity, 'blemishIntensity')}. ${customPrompts.skin}`;
  }

  // 3. Hair Studio Logic (Ombre & Texture)
  let hairText = "";
  if (enabledFeatures.hair) {
    const colorDesc = `hair with an expert ombre effect: roots in ${hair.hairColorTop} transitioning into a beautiful ${hair.hairColorBottom} for the length and ends`;
    const silhouette = `${hair.hairLength} length, ${hair.hairTexture} texture, with ${hair.bangStyle === 'none' ? 'no bangs' : hair.bangStyle + ' style bangs'}`;
    const volume = getSliderAdjective(hair.hairVolume, 'hairVolume');

    const refText = referenceImages.hair 
      ? "Strictly follow the HAIRSTYLE SILHOUETTE from Reference Image 1." 
      : `Silhouette: ${silhouette}. Volume: ${volume}.`;

    hairText = `HAIR STUDIO: ${refText} Color Palette: ${colorDesc}. ${customPrompts.hair}`;
  }

  // 4. Makeup Artist Logic (Eyebrows, Eyes, Lips, Blush)
  let makeupText = "";
  if (enabledFeatures.makeup) {
    const eyes = `${makeup.eyebrowStyle} eyebrows, ${makeup.eyelinerStyle} eyeliner, and ${makeup.eyelashStyle} lashes`;
    const eyeshadow = `eyeshadow applied in ${makeup.eyeshadowColor} color`;
    const blush = `${makeup.blushStyle} blush placement highlighted in ${makeup.blushColor} color at ${makeup.blushIntensity}% intensity`;
    const lips = `${makeup.lipStyle} lips painted in ${makeup.lipColor} color with ${makeup.lipstickGloss}% gloss`;

    const refText = referenceImages.makeup 
      ? "Strictly follow the MAKEUP ARTISTRY style from Reference Image 2." 
      : `Makeup Concept: ${makeup.makeupStyle}. Detailed specs: ${eyes}, ${eyeshadow}, ${blush}, ${lips}.`;

    makeupText = `MAKEUP ARTIST: ${refText} ${customPrompts.makeup}`;
  }

  return `Act as a world-class expert character artist, professional aesthetician, and high-end fashion retoucher.
    TASK: Synthesize the provided 'Base Image' with absolute precision using these character creation level parameters.

    IDENTITY PRESERVATION: You MUST preserve the fundamental identity of the person in the 'Base Image'. Keep the original clothing and background exactly as they are.

    EXPERT SYNTHESIS PARAMETERS:
    - FACIAL SCULPTING: ${enabledFeatures.face ? `Sculpt features to have: ${faceParts.join(", ")}. ${customPrompts.face}` : "Maintain original facial structure."}
    - ${hairText}
    - ${makeupText}
    - ${skinText}

    IMAGE PARTS GUIDE:
    - Base Image: The target identity to be modified.
    - Reference Image 1: Primary source for hair volume and silhouette.
    - Reference Image 2: Primary source for makeup blending and artistry logic.

    OUTPUT: 2K UHD Resolution, photorealistic editorial quality. Ensure perfect blending of the specified hex colors, natural lighting interaction, and anatomically correct hair and makeup textures.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);

  // Re-ordered payload for optimal synthesis results
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "Base Image" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.enabledFeatures.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "Reference Image 1" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.enabledFeatures.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "Reference Image 2" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

