export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, customPrompts, referenceImages } = state;

  // Targeted Editing Logic: If nothing is checked, it defaults to "Full Makeover"
  const isFullMakeover = !editModes.face && !editModes.skin && !editModes.hair && !editModes.makeup;
  const targetFace = isFullMakeover || editModes.face;
  const targetSkin = isFullMakeover || editModes.skin;
  const targetHair = isFullMakeover || editModes.hair;
  const targetMakeup = isFullMakeover || editModes.makeup;

  // 1. Facial Sculpting Logic
  let faceInstruction = "";
  if (targetFace) {
    const faceParts = [];
    Object.keys(features).forEach(key => {
      if (typeof (features as any)[key] === 'number') {
        faceParts.push(getSliderAdjective((features as any)[key], key));
      }
    });
    faceParts.push(`${features.eyelidType} eyelids`);
    faceInstruction = `Sculpt features to have: ${faceParts.join(", ")}. ${customPrompts.face}`;
  } else {
    faceInstruction = "STRICTLY keep the original facial structure, eye shape, nose shape, and mouth structure exactly as they appear in the Base Image. Do not morph the face.";
  }

  // 2. Skin Logic
  let skinInstruction = "";
  if (targetSkin) {
    const tone = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const textures = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ");
    skinInstruction = `Tone: ${tone} with ${textures}. Glow: ${getSliderAdjective(skin.glowIntensity, 'glowIntensity')}, Age: ${getSliderAdjective(skin.skinAge, 'skinAge')}, Texture: ${getSliderAdjective(skin.blemishIntensity, 'blemishIntensity')}. ${customPrompts.skin}`;
  } else {
    skinInstruction = "STRICTLY keep the original skin tone, complexion, and texture exactly as it is in the Base Image. Do not adjust skin.";
  }

  // 3. Hair Logic
  let hairInstruction = "";
  if (targetHair) {
    const colorDesc = `hair with an expert ombre effect: roots in ${hair.hairColorTop} transitioning into ${hair.hairColorBottom} for the length`;
    const silhouette = `${hair.hairLength} length, ${hair.hairTexture} texture, with ${hair.bangStyle === 'none' ? 'no bangs' : hair.bangStyle + ' style bangs'}`;
    const volume = getSliderAdjective(hair.hairVolume, 'hairVolume');
    const refText = referenceImages.hair ? "Strictly follow the HAIRSTYLE SILHOUETTE from Reference Image 1." : `Silhouette: ${silhouette}. Volume: ${volume}.`;
    hairInstruction = `${refText} Color: ${colorDesc}. ${customPrompts.hair}`;
  } else {
    hairInstruction = "STRICTLY keep the original hairstyle, hair volume, and hair color exactly as they are in the Base Image. Do not modify hair.";
  }

  // 4. Makeup Logic
  let makeupInstruction = "";
  if (targetMakeup) {
    const eyes = `${makeup.eyebrowStyle} eyebrows, ${makeup.eyelinerStyle} eyeliner, and ${makeup.eyelashStyle} lashes`;
    const eyeshadow = `eyeshadow applied in ${makeup.eyeshadowColor} color`;
    const blush = `${makeup.blushStyle} blush placement highlighted in ${makeup.blushColor} color at ${makeup.blushIntensity}% intensity`;
    const lips = `${makeup.lipStyle} lips painted in ${makeup.lipColor} color with ${makeup.lipstickGloss}% gloss`;
    const refText = referenceImages.makeup ? "Strictly follow the MAKEUP ARTISTRY style from Reference Image 2." : `Concept: ${makeup.makeupStyle}. Specs: ${eyes}, ${eyeshadow}, ${blush}, ${lips}.`;
    makeupInstruction = `${refText} ${customPrompts.makeup}`;
  } else {
    makeupInstruction = "STRICTLY keep the original makeup exactly as is. If the person has no makeup, maintain the no-makeup look. Do not add cosmetics.";
  }

  return `Act as a world-class expert character artist and fashion retoucher.
    TASK: Synthesize the provided 'Base Image' based on the specific edits requested below.

    IDENTITY PRESERVATION: You MUST preserve the fundamental identity of the person in the 'Base Image'. Keep the original clothing and background perfectly intact.

    ${isFullMakeover ? "MODE: FULL MAKEOVER - Perform a high-end editorial transformation." : "MODE: TARGETED EDITING - Only modify the categories explicitly enabled below."}

    EDITING PARAMETERS:
    - FACIAL SCULPTING: ${faceInstruction}
    - HAIR STUDIO: ${hairInstruction}
    - MAKEUP ARTIST: ${makeupInstruction}
    - SKIN & COMPLEXION: ${skinInstruction}

    ASSET GUIDE:
    - Base Image: The target identity.
    - Reference Image 1: Hair silhouette source (if provided).
    - Reference Image 2: Makeup logic source (if provided).

    OUTPUT: 2K UHD Resolution, photorealistic editorial finish. Ensure perfect blending and professional lighting.`;
};

