import { BeautyState } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      hair: null,
      makeup: null
    },
    features: INITIAL_FEATURES,
    skin: { 
      tone: 'natural', 
      texture: ['Smooth'],
      skinAge: 20,
      glowIntensity: 50,
      blemishIntensity: 10
    },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customPrompts: {
      face: '',
      skin: '',
      hair: '',
      makeup: ''
    },
    editModes: {
      face: false,
      skin: false,
      hair: false,
      makeup: false
    },
    aspectRatio: '1:1'
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_2K_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    updateState({ 
      baseImage: generatedImage,
    });
    setGeneratedImage(null);
    setIsComparing(false);
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const calculateAspectRatio = (img: HTMLImageElement): "1:1" | "3:4" | "4:3" | "9:16" | "16:9" => {
    const ratio = img.width / img.height;
    const options: { label: "1:1" | "3:4" | "4:3" | "9:16" | "16:9", value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = () => {
            const ratio = calculateAspectRatio(img);
            updateState({ baseImage: base64String, aspectRatio: ratio });
          };
          img.src = base64String;
        } else {
          updateState({ 
            referenceImages: { 
              ...state.referenceImages, 
              [type]: base64String 
            } 
          });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) {
    return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;
  }

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden text-zinc-100">
      <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/80 backdrop-blur-xl z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Sparkles className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight">BeautySynth <span className="text-indigo-500">PRO</span></h1>
            <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">Expert Medical Facial Synthesis</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={handleGenerate}
            disabled={isGenerating || !state.baseImage}
            className={`flex items-center gap-2 px-8 py-2.5 rounded-full font-bold transition-all ${
              isGenerating || !state.baseImage
              ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed opacity-50' 
              : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-xl shadow-indigo-600/20'
            }`}
          >
            {isGenerating ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'Synthesizing (2K)...' : 'Generate Synthesis'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar state={state} updateState={updateState} onRefUpload={onFileUpload} />

        <div className="flex-1 p-6 flex flex-col gap-6 overflow-hidden bg-zinc-950">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-xl flex items-center justify-between text-sm shrink-0">
              <span>{error}</span>
              <button onClick={() => setError(null)}>✕</button>
            </div>
          )}

          <div className="flex flex-col flex-1 min-h-0 gap-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-0">
              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative group shadow-inner">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Input: Base Image</h3>
                  {state.baseImage && (
                    <button onClick={() => updateState({ baseImage: null })} className="text-zinc-600 hover:text-red-400">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                </div>
                <div className="flex-1 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-zinc-900 to-black overflow-hidden">
                  {state.baseImage ? (
                    <img src={state.baseImage} className="max-w-full max-h-full object-contain" alt="Base" />
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-4">
                      <div className="w-20 h-20 rounded-full bg-zinc-800 flex items-center justify-center text-zinc-500 hover:text-indigo-400 transition-colors border border-zinc-700">
                        <Upload className="w-8 h-8" />
                      </div>
                      <span className="text-zinc-500 font-medium text-sm">Upload Base Image</span>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
              </div>

              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative shadow-2xl">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Synthesis Result: 2K UHD</h3>
                  <div className="flex gap-2">
                    {generatedImage && (
                      <>
                        <button 
                          onClick={handleUseAsBase}
                          className="text-[10px] font-bold uppercase tracking-widest text-indigo-400 flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-500/10 border border-indigo-500/20 active:scale-95 transition-all hover:bg-indigo-500/20"
                          title="Use result as base"
                        >
                          <RefreshCcw className="w-3 h-3" />
                          Use as Base
                        </button>
                        <button 
                          onClick={handleDownload}
                          className="text-[10px] font-bold uppercase tracking-widest text-emerald-400 flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20 active:scale-95 transition-all hover:bg-emerald-500/20"
                        >
                          <Download className="w-3 h-3" />
                          Download
                        </button>
                        <button 
                          onMouseDown={() => setIsComparing(true)}
                          onMouseUp={() => setIsComparing(false)}
                          onMouseLeave={() => setIsComparing(false)}
                          className="text-[10px] font-bold uppercase tracking-widest text-zinc-400 flex items-center gap-2 px-3 py-1 rounded-full bg-zinc-500/10 border border-zinc-500/20 active:scale-95 select-none transition-all hover:bg-zinc-500/20"
                        >
                          {isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />}
                          Compare
                        </button>
                      </>
                    )}
                  </div>
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas 
                    image={isComparing ? state.baseImage : generatedImage} 
                    loading={isGenerating}
                    onDownload={handleDownload}
                  />
                  {isComparing && (
                    <div className="absolute top-4 left-4 px-3 py-1 bg-black/80 text-[10px] font-bold text-white uppercase tracking-widest rounded-full border border-white/20">
                      Original
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl p-4 flex flex-col gap-2 shrink-0 h-28 shadow-inner overflow-hidden">
              <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                <Zap className="w-3 h-3 text-indigo-500" /> Targeted Synthesis Prompt Preview
              </h3>
              <div className="flex-1 overflow-y-auto text-[11px] text-zinc-400 leading-relaxed font-mono bg-black/30 p-3 rounded-xl border border-zinc-800/50">
                {currentPrompt}
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useCallback, useState } from 'react';
import { BeautyState } from '../types';
import { 
  SKIN_TONES, SKIN_TEXTURES, HAIR_COLOR_PRESETS, MAKEUP_PRESETS,
  HAIR_LENGTHS, HAIR_TEXTURES, BANG_STYLES,
  EYEBROW_STYLES, EYELINER_STYLES, EYELASH_STYLES, BLUSH_STYLES, LIP_STYLES
} from '../constants';
import { 
  User, Droplets, Scissors, Zap, Activity, ToggleLeft, ToggleRight, MessageSquareText, 
  Upload, Trash2, Image as ImageIcon, Palette, Pipette, ChevronDown, ChevronRight, 
  Scan, Smile, Eye, Brush, Sparkles, CheckSquare, Square
} from 'lucide-react';

interface SidebarProps {
  state: BeautyState;
  updateState: (updates: Partial<BeautyState>) => void;
  onRefUpload: (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => void;
}

const CategoryAccordion = ({ title, icon: Icon, children, defaultOpen = false }: { title: string, icon: any, children?: React.ReactNode, defaultOpen?: boolean }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  return (
    <div className="border-b border-zinc-900 last:border-0">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between py-4 text-left group hover:bg-zinc-900/30 px-4 transition-all"
      >
        <div className="flex items-center gap-3">
          <div className={`p-1.5 rounded-lg transition-colors ${isOpen ? 'bg-indigo-500/10 text-indigo-400' : 'bg-zinc-900 text-zinc-500'}`}>
            <Icon className="w-3.5 h-3.5" />
          </div>
          <span className={`text-[10px] font-bold uppercase tracking-widest transition-colors ${isOpen ? 'text-zinc-200' : 'text-zinc-500 group-hover:text-zinc-300'}`}>{title}</span>
        </div>
        {isOpen ? <ChevronDown className="w-3 h-3 text-zinc-600" /> : <ChevronRight className="w-3 h-3 text-zinc-600" />}
      </button>
      {isOpen && (
        <div className="px-4 pb-6 space-y-6 animate-in fade-in slide-in-from-top-1 duration-200">
          {children}
        </div>
      )}
    </div>
  );
};

const ColorSection = React.memo(({ 
  label, 
  id,
  presets, 
  colorValue, 
  disabled, 
  onColorChange 
}: { 
  label: string, 
  id: string,
  presets: {color: string, label: string}[],
  colorValue: string,
  disabled: boolean,
  onColorChange: (id: string, value: string) => void
}) => {
  const inputRef = useRef<HTMLInputElement>(null);
  const handlePickerClick = () => {
    if (!disabled && inputRef.current) inputRef.current.click();
  };

  return (
    <div className="space-y-3">
      <div className="flex justify-between items-center">
        <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">{label}</span>
        <div className="flex items-center gap-2">
          <span className="text-[8px] font-mono text-zinc-600 uppercase">{colorValue}</span>
          <div 
            onClick={handlePickerClick}
            className={`relative cursor-pointer group w-5 h-5 rounded-md border border-zinc-700 overflow-hidden shadow-inner flex items-center justify-center transition-all ${disabled ? 'opacity-50 grayscale cursor-not-allowed' : 'hover:border-indigo-500 hover:scale-105 active:scale-95'}`}
          >
            <div className="w-full h-full" style={{ backgroundColor: colorValue }} />
            <Pipette className="w-2.5 h-2.5 text-white absolute mix-blend-difference opacity-0 group-hover:opacity-100 transition-opacity" />
            <input 
              ref={inputRef}
              type="color" 
              className="absolute inset-0 opacity-0 pointer-events-none w-0 h-0"
              value={colorValue}
              disabled={disabled}
              onInput={(e) => onColorChange(id, (e.target as HTMLInputElement).value)}
              onChange={(e) => onColorChange(id, (e.target as HTMLInputElement).value)}
            />
          </div>
        </div>
      </div>
      <div className="flex flex-wrap gap-1 p-1.5 bg-black/20 rounded-xl border border-zinc-800/30">
        {presets.map((p, idx) => (
          <button
            key={idx}
            disabled={disabled}
            onClick={() => onColorChange(id, p.color)}
            className={`w-5 h-5 rounded-md border transition-all ${colorValue === p.color ? 'border-indigo-500 scale-110 shadow-lg shadow-indigo-500/20' : 'border-transparent hover:border-zinc-700'}`}
            style={{ backgroundColor: p.color }}
            title={p.label}
          />
        ))}
      </div>
    </div>
  );
});

export const StudioSidebar: React.FC<SidebarProps> = ({ state, updateState, onRefUpload }) => {
  const handleFeatureChange = useCallback((key: string, value: any) => {
    updateState({ features: { ...state.features, [key]: value } });
  }, [state.features, updateState]);

  const handleMakeupChange = useCallback((id: string, value: any) => {
    updateState({ makeup: { ...state.makeup, [id]: value } });
  }, [state.makeup, updateState]);

  const handleHairChange = useCallback((id: string, value: any) => {
    updateState({ hair: { ...state.hair, [id]: value } });
  }, [state.hair, updateState]);

  const handleSkinChange = useCallback((id: string, value: any) => {
    updateState({ skin: { ...state.skin, [id]: value } });
  }, [state.skin, updateState]);

  const handleCustomPromptChange = useCallback((category: keyof BeautyState['customPrompts'], value: string) => {
    updateState({
      customPrompts: {
        ...state.customPrompts,
        [category]: value
      }
    });
  }, [state.customPrompts, updateState]);

  const toggleEditMode = (mode: keyof BeautyState['editModes']) => {
    updateState({
      editModes: {
        ...state.editModes,
        [mode]: !state.editModes[mode]
      }
    });
  };

  const renderRefUploader = (category: 'face' | 'skin' | 'hair' | 'makeup', label: string) => (
    <div className="space-y-3 pt-4 border-t border-zinc-900">
      <div className="flex items-center justify-between text-zinc-500">
        <div className="flex items-center gap-2">
          <ImageIcon className="w-3 h-3" />
          <span className="text-[10px] font-bold uppercase tracking-widest">{label} Ref</span>
        </div>
        {state.referenceImages[category] && (
          <button onClick={() => updateState({ referenceImages: { ...state.referenceImages, [category]: null }})} className="text-zinc-600 hover:text-red-400">
            <Trash2 className="w-3 h-3" />
          </button>
        )}
      </div>
      <div className="relative aspect-video bg-zinc-900/50 border border-dashed border-zinc-800 rounded-xl overflow-hidden flex items-center justify-center hover:bg-zinc-900 transition-colors group">
        {state.referenceImages[category] ? (
          <img src={state.referenceImages[category]!} className="w-full h-full object-contain" alt="Reference" />
        ) : (
          <label className="cursor-pointer w-full h-full flex flex-col items-center justify-center gap-2">
            <Upload className="w-4 h-4 text-zinc-600 group-hover:text-indigo-400" />
            <input type="file" className="hidden" accept="image/*" onChange={onRefUpload(category)} />
          </label>
        )}
      </div>
    </div>
  );

  return (
    <aside className="w-80 border-r border-zinc-900 bg-zinc-950 flex flex-col h-full z-20">
      <div className="p-6 border-b border-zinc-900 bg-black/40">
        <div className="flex items-center gap-2 mb-4">
          <Zap className="w-4 h-4 text-indigo-500" />
          <h3 className="text-[10px] font-bold uppercase tracking-widest text-zinc-300">Edit Mode Selector</h3>
        </div>
        <div className="grid grid-cols-2 gap-2">
          {[
            { id: 'skin', label: 'Skin', icon: Droplets },
            { id: 'face', label: 'Features', icon: Scan },
            { id: 'hair', label: 'Hair', icon: Scissors },
            { id: 'makeup', label: 'Makeup', icon: Brush },
          ].map((mode) => (
            <button
              key={mode.id}
              onClick={() => toggleEditMode(mode.id as any)}
              className={`flex items-center gap-2 px-3 py-2 rounded-xl border text-[10px] font-bold transition-all ${
                state.editModes[mode.id as keyof BeautyState['editModes']]
                  ? 'bg-indigo-600/10 border-indigo-500 text-indigo-400'
                  : 'bg-zinc-900/50 border-zinc-800 text-zinc-500 hover:border-zinc-700'
              }`}
            >
              {state.editModes[mode.id as keyof BeautyState['editModes']] ? (
                <CheckSquare className="w-3.5 h-3.5" />
              ) : (
                <Square className="w-3.5 h-3.5" />
              )}
              {mode.label}
            </button>
          ))}
        </div>
        {!Object.values(state.editModes).some(v => v) && (
          <p className="mt-3 text-[9px] text-zinc-500 font-medium italic text-center">
            * No modes selected: "Full Makeover" enabled.
          </p>
        )}
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar">
        <CategoryAccordion title="Skin & Base" icon={Droplets} defaultOpen={true}>
          <div className="space-y-5">
            <div className="flex flex-wrap gap-2">
              {SKIN_TONES.map(tone => (
                <button
                  key={tone.id}
                  onClick={() => handleSkinChange('tone', tone.id)}
                  className={`relative w-8 h-8 rounded-full border-2 transition-all ${state.skin.tone === tone.id ? 'border-indigo-500 scale-110 shadow-lg' : 'border-zinc-800'}`}
                  style={{ backgroundColor: tone.color }}
                  title={tone.label}
                />
              ))}
            </div>
            {[
              { label: 'Skin Age (Youth/Mature)', key: 'skinAge' },
              { label: 'Glow (Matte/Oily)', key: 'glowIntensity' },
              { label: 'Natural Blemishes', key: 'blemishIntensity' },
            ].map(f => (
              <div key={f.key} className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold">
                  <span className="text-zinc-500">{f.label}</span>
                  <span className="text-indigo-400">{(state.skin as any)[f.key]}</span>
                </div>
                <input 
                  type="range" min="0" max="100" 
                  value={(state.skin as any)[f.key]}
                  onChange={(e) => handleSkinChange(f.key, parseInt(e.target.value))}
                  className="w-full accent-indigo-600 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" 
                />
              </div>
            ))}
            <div className="grid grid-cols-2 gap-2">
              {SKIN_TEXTURES.map(texture => (
                <button
                  key={texture.id}
                  onClick={() => {
                    const newTextures = state.skin.texture.includes(texture.id)
                      ? state.skin.texture.filter(t => t !== texture.id)
                      : [...state.skin.texture, texture.id];
                    handleSkinChange('texture', newTextures);
                  }}
                  className={`px-3 py-2 rounded-xl text-[9px] font-bold border transition-all ${
                    state.skin.texture.includes(texture.id)
                    ? 'bg-indigo-600/20 border-indigo-500 text-indigo-400'
                    : 'bg-zinc-900/50 border-zinc-800 text-zinc-600 hover:border-zinc-700'
                  }`}
                >
                  {texture.label}
                </button>
              ))}
            </div>
            {renderRefUploader('skin', 'Skin')}
          </div>
        </CategoryAccordion>

        <CategoryAccordion title="Eyes & Brows" icon={Eye}>
          <div className="space-y-5">
            {[
              { label: 'Eyebrow Style', key: 'eyebrowStyle', options: EYEBROW_STYLES },
              { label: 'Eyeliner Style', key: 'eyelinerStyle', options: EYELINER_STYLES },
              { label: 'Eyelash Effect', key: 'eyelashStyle', options: EYELASH_STYLES },
            ].map(f => (
              <div key={f.key} className="space-y-2">
                <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">{f.label}</span>
                <div className="grid grid-cols-2 gap-1">
                  {f.options.map((opt: any) => (
                    <button
                      key={opt.id}
                      onClick={() => handleMakeupChange(f.key, opt.id)}
                      className={`py-2 rounded-lg text-[9px] font-bold border transition-all ${state.makeup[f.key as keyof typeof state.makeup] === opt.id ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-zinc-900/50 border-zinc-800 text-zinc-600'}`}
                    >
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>
            ))}
            {[
              { label: 'Eye Size', key: 'eyeSize' },
              { label: 'Eye Tilt (Cat/Puppy)', key: 'canthalTilt' },
              { label: 'Eye Distance', key: 'eyeDistance' },
            ].map(f => (
              <div key={f.key} className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold">
                  <span className="text-zinc-500">{f.label}</span>
                  <span className="text-indigo-400">{(state.features as any)[f.key]}</span>
                </div>
                <input 
                  type="range" min="0" max="100" 
                  value={(state.features as any)[f.key]}
                  onChange={(e) => handleFeatureChange(f.key, parseInt(e.target.value))}
