                        </div>
                        <input 
                          type="range" min="0" max="100" 
                          value={(state.features as any)[f.key]}
                          onChange={(e) => handleFeatureChange(f.key, parseInt(e.target.value))}
                          className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" 
                        />
                      </div>
                    ))}
                    <div className="grid grid-cols-3 gap-1">
                      {['Monolid', 'Double', 'Hooded'].map(type => (
                        <button
                          key={type}
                          onClick={() => handleFeatureChange('eyelidType', type)}
                          className={`py-2 rounded-lg text-[9px] font-bold border transition-all ${state.features.eyelidType === type ? 'bg-rose-500/20 border-rose-400 text-rose-300' : 'bg-zinc-900/50 border-zinc-800 text-zinc-600'}`}
                        >
                          {type}
                        </button>
                      ))}
                    </div>
                  </div>
                </CategoryAccordion>

                <CategoryAccordion title="Nose & Lips Sculpting" icon={Smile}>
                  <div className="space-y-5">
                    {[
                      { label: 'Nose Bridge', key: 'noseBridge' },
                      { label: 'Lip Volume', key: 'lipThickness' },
                      { label: 'Jawline Sharpness', key: 'jawlineSharpness' },
                      { label: 'Face Width', key: 'faceWidth' },
                    ].map(f => (
                      <div key={f.key} className="space-y-2">
                        <div className="flex justify-between text-[10px] font-bold">
                          <span className="text-zinc-500">{f.label}</span>
                          <span className="text-rose-400">{(state.features as any)[f.key]}</span>
                        </div>
                        <input 
                          type="range" min="0" max="100" 
                          value={(state.features as any)[f.key]}
                          onChange={(e) => handleFeatureChange(f.key, parseInt(e.target.value))}
                          className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" 
                        />
                      </div>
                    ))}
                    {renderRefUploader('face', 'Facial')}
                  </div>
                </CategoryAccordion>
              </>
            )}

            {/* Hair Category */}
            {state.editModes.hair && (
              <CategoryAccordion title="Hair Studio" icon={Scissors} onOpenHelp={() => setActiveHelpModal('hair')}>
                <div className="space-y-5">
                  <div className="space-y-2">
                    <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">Length</span>
                    <div className="grid grid-cols-3 gap-1">
                      {HAIR_LENGTHS.map(len => (
                        <button
                          key={len.id}
                          onClick={() => handleHairChange('hairLength', len.id)}
                          className={`py-2 rounded-lg text-[9px] font-bold border transition-all ${state.hair.hairLength === len.id ? 'bg-rose-500 text-white border-rose-400' : 'bg-zinc-900/50 border-zinc-800 text-zinc-600'}`}
                        >
                          {len.label}
                        </button>
                      ))}
                    </div>
                  </div>
                  <div className="space-y-2">
                    <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">Texture</span>
                    <div className="grid grid-cols-3 gap-1">
                      {HAIR_TEXTURES.map(tex => (
                        <button
                          key={tex.id}
                          onClick={() => handleHairChange('hairTexture', tex.id)}
                          className={`py-2 rounded-lg text-[9px] font-bold border transition-all ${state.hair.hairTexture === tex.id ? 'bg-rose-500 text-white border-rose-400' : 'bg-zinc-900/50 border-zinc-800 text-zinc-600'}`}
                        >
                          {tex.label}
                        </button>
                      ))}
                    </div>
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold">
                      <span className="text-zinc-500">Volume</span>
                      <span className="text-rose-400">{state.hair.hairVolume}</span>
                    </div>
                    <input 
                      type="range" min="0" max="100" 
                      value={state.hair.hairVolume}
                      onChange={(e) => handleHairChange('hairVolume', parseInt(e.target.value))}
                      className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" 
                    />
                  </div>
                  <ColorSection label="Root Color" id="hairColorTop" presets={HAIR_COLOR_PRESETS} colorValue={state.hair.hairColorTop} disabled={false} onColorChange={handleHairChange} />
                  <ColorSection label="Ends Color" id="hairColorBottom" presets={HAIR_COLOR_PRESETS} colorValue={state.hair.hairColorBottom} disabled={false} onColorChange={handleHairChange} />
                  {renderRefUploader('hair', 'Hair')}
                </div>
              </CategoryAccordion>
            )}

            {/* Makeup Category */}
            {state.editModes.makeup && (
              <CategoryAccordion title="Makeup Artist" icon={Brush} onOpenHelp={() => setActiveHelpModal('makeup')}>
                <div className="space-y-5">
                  <select 
                    value={state.makeup.makeupStyle}
                    onChange={(e) => handleMakeupChange('makeupStyle', e.target.value)}
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 text-[11px] font-bold text-zinc-300 outline-none focus:border-rose-400"
                  >
                    {MAKEUP_STYLES.map(style => (
                      <option key={style.id} value={style.id}>{style.label}</option>
                    ))}
                  </select>
                  <ColorSection label="Eyeshadow" id="eyeshadowColor" presets={MAKEUP_PRESETS.eyeshadow} colorValue={state.makeup.eyeshadowColor} disabled={false} onColorChange={handleMakeupChange} />
                  <div className="space-y-2">
                    <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">Lip Finish</span>
                    <div className="grid grid-cols-2 gap-1">
                      {LIP_STYLES.map(style => (
                        <button
                          key={style.id}
                          onClick={() => handleMakeupChange('lipStyle', style.id)}
                          className={`py-2 rounded-lg text-[9px] font-bold border transition-all ${state.makeup.lipStyle === style.id ? 'bg-rose-500 text-white border-rose-400' : 'bg-zinc-900/50 border-zinc-800 text-zinc-600'}`}
                        >
                          {style.label}
                        </button>
                      ))}
                    </div>
                  </div>
                  <ColorSection label="Lip Color" id="lipColor" presets={MAKEUP_PRESETS.lipstick} colorValue={state.makeup.lipColor} disabled={false} onColorChange={handleMakeupChange} />
                  <div className="space-y-3 pt-4 border-t border-zinc-900">
                    <div className="flex items-center gap-2 text-zinc-500">
                      <Sparkles className="w-3 h-3" />
                      <span className="text-[9px] font-bold uppercase tracking-widest">Additional Effects</span>
                    </div>
                    <textarea 
                      value={state.customPrompts.makeup}
                      onChange={(e) => handleCustomPromptChange('makeup', e.target.value)}
                      placeholder="High-gloss, glitter, specific style..."
                      className="w-full h-20 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-[10px] text-zinc-300 outline-none focus:border-rose-400 transition-all resize-none"
                    />
                  </div>
                  {renderRefUploader('makeup', 'Makeup')}
                </div>
              </CategoryAccordion>
            )}
          </div>
        )}
      </div>

      <div className="p-4 bg-zinc-950 border-t border-zinc-900">
        <div className="flex items-center gap-2 text-rose-400 mb-1">
          <Zap className="w-3 h-3 fill-current" />
          <span className="text-[9px] font-bold uppercase tracking-widest">Context Engine v7.0</span>
        </div>
        <p className="text-[10px] text-zinc-600 leading-tight">Dynamic UI active. Only editing enabled modules.</p>
      </div>
    </aside>
  );
};

