        )}
      </div>
    </div>
  );

  const hasActiveModes = Object.values(state.editModes).some(v => v);

  return (
    <aside className="w-80 border-r border-zinc-900 bg-zinc-950 flex flex-col h-full z-20">
      {/* Right-Side Sliding Help Drawer (Non-blocking) */}
      <div 
        className={`fixed top-0 right-0 h-full w-[350px] bg-[#1a1a1a] border-l border-[#fb7185] shadow-2xl z-[60] overflow-y-auto p-6 transition-transform duration-300 ease-in-out transform ${
          activeHelpId ? 'translate-x-0' : 'translate-x-full'
        }`}
      >
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-lg font-bold text-rose-400">
            {activeHelpId && HELP_CONTENT[activeHelpId].title}
          </h3>
          <button 
            onClick={() => setActiveHelpId(null)}
            className="p-2 rounded-full hover:bg-zinc-800 text-zinc-400 hover:text-white transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>
        <div className="h-px bg-rose-400/20 mb-6" />
        <div className="text-[13px] text-zinc-300 leading-relaxed whitespace-pre-wrap font-medium">
          {activeHelpId && HELP_CONTENT[activeHelpId].desc}
        </div>

        <div className="mt-12 p-4 bg-rose-400/5 border border-rose-400/10 rounded-xl">
          <p className="text-[11px] text-rose-300/60 leading-tight">
