                    ))}
                    {[
                      { label: 'Eye Size', key: 'eyeSize' },
                      { label: 'Eye Tilt (Cat/Puppy)', key: 'canthalTilt' },
                      { label: 'Nose Bridge', key: 'noseBridge' },
                      { label: 'Lip Volume', key: 'lipThickness' },
                      { label: 'Jawline Sharpness', key: 'jawlineSharpness' },
                      { label: 'Face Width', key: 'faceWidth' },
