                    <div className="flex items-center gap-2 text-zinc-500">
                      <Sparkles className="w-3 h-3" />
                      <span className="text-[9px] font-bold uppercase tracking-widest">Additional Effects</span>
                    </div>
                    <textarea 
                      value={state.customPrompts.makeup}
                      onChange={(e) => handleCustomPromptChange('makeup', e.target.value)}
                      placeholder="High-gloss, glitter, specific style..."
                      className="w-full h-20 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-[10px] text-zinc-300 outline-none focus:border-rose-400 transition-all resize-none"
                    />
                  </div>
                  {renderRefUploader('makeup', 'Makeup')}
                </div>
              </CategoryAccordion>
            )}
          </div>
        )}
      </div>

      <div className="p-4 bg-zinc-950 border-t border-zinc-900">
        <div className="flex items-center gap-2 text-rose-400 mb-1">
          <Zap className="w-3 h-3 fill-current" />
          <span className="text-[9px] font-bold uppercase tracking-widest">Context Engine v7.0</span>
        </div>
        <p className="text-[10px] text-zinc-600 leading-tight">Dynamic UI active. Only editing enabled modules.</p>
      </div>
    </aside>
  );
};

