                          <button
                            key={type}
                            onClick={() => handleFeatureChange('eyelidType', type)}
                            className={`py-2 rounded-lg text-[9px] font-bold border transition-all ${state.features.eyelidType === type ? 'bg-indigo-500/20 border-indigo-400 text-indigo-300' : 'bg-zinc-900/50 border-zinc-800 text-zinc-600'}`}
                          >
