  eyelashStyle: 'natural' | 'mascara' | 'idol_lashes' | 'false_lashes';
  eyeshadowColor: string;
  eyelinerIntensity: number;
  blushStyle: 'none' | 'apples' | 'drunken' | 'contour';
  blushColor: string;
  blushIntensity: number;
  contourIntensity: number;
  lipStyle: 'matte_full' | 'glossy_full' | 'gradient_tint' | 'overlined';
  lipColor: string;
  lipstickGloss: number;
}

export interface BeautyState {
  baseImage: string | null;
  referenceImages: {
    face: string | null;
    skin: string | null;
    hair: string | null;
    makeup: string | null;
  };
  features: FacialFeatures;
  skin: SkinFeatures;
  hair: HairFeatures;
