/**
 * 차이 기반 프롬프트 생성 (Diff-Based Prompting)
 * 사용자가 슬라이더를 옮기지 않았다면 "원래 형태 유지"를 명시합니다.
 */
const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline !== undefined && Math.abs(current - baseline) < 5) {
    return `strictly preserve the original ${type} exactly as in the base image`;
  }
  return getSliderAdjective(current, type);
};

/**
 * AI 이미지 분석: 업로드된 이미지에서 얼굴 특징을 추출하여 초기 상태값을 설정합니다.
 */
export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data, mimeType } },
          { text: "Analyze the facial features of the person in this image and estimate the following attributes on a scale of 0-100. Return ONLY a JSON object." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            skinTone: { type: Type.NUMBER, description: "0: Pale/Porcelain, 100: Dark/Deep" },
            skinAge: { type: Type.NUMBER, description: "0: Baby, 100: Old" },
            eyeSize: { type: Type.NUMBER, description: "0: Small, 100: Large" },
            eyeTilt: { type: Type.NUMBER, description: "0: Puppy(Down), 100: Cat(Up)" },
            noseBridge: { type: Type.NUMBER, description: "0: Low, 100: High" },
            jawShape: { type: Type.NUMBER, description: "0: Round, 100: Sharp V-line" },
            lipFullness: { type: Type.NUMBER, description: "0: Thin, 100: Thick" },
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] },
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] }
          },
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "jawShape", "lipFullness", "hairLength", "hairTexture"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return result;
  } catch (error) {
    console.error("Attribute Analysis Error:", error);
    throw error;
  }
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, customPrompts, referenceImages, baseline } = state;

  const isFullMakeover = !editModes.face && !editModes.skin && !editModes.hair && !editModes.makeup;
  const targetFace = isFullMakeover || editModes.face;
  const targetSkin = isFullMakeover || editModes.skin;
  const targetHair = isFullMakeover || editModes.hair;
  const targetMakeup = isFullMakeover || editModes.makeup;

  let faceInstruction = "";
  if (targetFace) {
    const faceParts: string[] = [];

    // Use diff-based logic for features detected by analysis
    faceParts.push(getDiffFeaturePrompt(features.eyeSize, baseline?.features.eyeSize, 'eye size'));
    faceParts.push(getDiffFeaturePrompt(features.canthalTilt, baseline?.features.canthalTilt, 'eye tilt'));
    faceParts.push(getDiffFeaturePrompt(features.noseBridge, baseline?.features.noseBridge, 'nose bridge'));
    faceParts.push(getDiffFeaturePrompt(features.jawShape, baseline?.features.jawShape, 'jaw shape'));
    faceParts.push(getDiffFeaturePrompt(features.lipThickness, baseline?.features.lipThickness, 'lip thickness'));

    // Other features not analyzed continue with standard logic
    const otherKeys: (keyof FacialFeatures)[] = ['noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'mouthCorners', 'lipCupidBow'];
    otherKeys.forEach(key => {
      const value = features[key];
      if (typeof value === 'number') {
        faceParts.push(getSliderAdjective(value, key));
      }
    });

    let browPrompt = "";
    switch (makeup.eyebrowStyle) {
      case 'straight':
        browPrompt = "linear straight eyebrows, horizontal K-beauty brow shape, minimized arch, flattened brow line";
        break;
      case 'arched':
        browPrompt = "high-arched sharp eyebrows, western angular brow shape, lifted tail";
        break;
      case 'bushy':
        browPrompt = "bushy wild texture eyebrows, individual hair strands visible, fluffy look";
        break;
      default:
        browPrompt = "clean natural eyebrows";
    }

    const eyeStructure = `${browPrompt}, ${makeup.eyelinerStyle} eyeliner technique, and ${makeup.eyelashStyle} lash volume`;

    faceInstruction = `Sculpt facial structure and eyes: ${faceParts.join(", ")}. 
      Eye details: ${eyeStructure} with ${features.eyelidType} eyelids.`;

    if (makeup.eyebrowStyle === 'straight') {
      faceInstruction += " CRITICAL: Reduce eyebrow arch height to be strictly horizontal and linear.";
    }

    faceInstruction += ` ${customPrompts.face}`;
  } else {
    faceInstruction = "STRICTLY preserve the original facial structure, eye shape, eyebrows, and lashes exactly. Do not morph the face structure.";
  }

  let skinInstruction = "";
  if (targetSkin) {
    const tone = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const textures = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ");

    const skinToneEmphasized = (baseline?.skin.tone === skin.tone) 
      ? `strictly preserve the original ${tone} complexion` 
      : `change complexion to ${tone}`;

    const skinAgePrompt = getDiffFeaturePrompt(skin.skinAge, baseline?.skin.skinAge, 'skin age');

    skinInstruction = `${skinToneEmphasized} with ${textures}. Glow: ${getSliderAdjective(skin.glowIntensity, 'glowIntensity')}, Age: ${skinAgePrompt}, Texture: ${getSliderAdjective(skin.blemishIntensity, 'blemishIntensity')}.`;

    // 주근깨 보존을 위한 강력한 예외 지시어
    if (skin.texture.includes('Freckles')) {
      skinInstruction += " CRITICAL: Do NOT airbrush or smooth out the freckles; ensure they are sharp, high-contrast, and naturally visible.";
    }

    skinInstruction += ` ${customPrompts.skin}`;
  } else {
    skinInstruction = "STRICTLY preserve the original skin tone and texture exactly as in the source image.";
  }

  let hairInstruction = "";
  if (targetHair) {
    const colorDesc = `hair with ombre effect: ${hair.hairColorTop} to ${hair.hairColorBottom}`;
    const silhouette = `${hair.hairLength} length, ${hair.hairTexture} texture, with ${hair.bangStyle} style bangs`;
    const volume = getSliderAdjective(hair.hairVolume, 'hairVolume');
    const refText = referenceImages.hair ? "Strictly follow the HAIRSTYLE from Reference Image 1." : `Silhouette: ${silhouette}. Volume: ${volume}.`;
    hairInstruction = `${refText} Color: ${colorDesc}. ${customPrompts.hair}`;
  } else {
    hairInstruction = "STRICTLY preserve the original hairstyle and hair color exactly.";
  }

  let makeupInstruction = "";
  if (targetMakeup) {
    const eyeshadow = `eyeshadow in ${makeup.eyeshadowColor}`;
    const blush = `${makeup.blushStyle} blush in ${makeup.blushColor} at ${makeup.blushIntensity}% intensity`;
    const shading = `contouring with ${getSliderAdjective(makeup.contourIntensity, 'contourIntensity')}`;
    const lips = `${makeup.lipStyle} lips in ${makeup.lipColor} with ${makeup.lipstickGloss}% gloss`;

    const refText = referenceImages.makeup ? "Strictly follow the COLOR PALETTE and CONCEPT from Reference Image 2." : `Concept: ${makeup.makeupStyle}. Specs: ${eyeshadow}, ${blush}, ${shading}, ${lips}.`;
    makeupInstruction = `${refText} ${customPrompts.makeup}`;
  } else {
    makeupInstruction = "STRICTLY preserve original eyeshadow, lipstick, and blush colors. No new color makeup or changes to existing makeup.";
  }

  return `Act as a world-class expert character artist and fashion retoucher.
    TASK: Synthesize the provided 'Base Image' based on the specific edits requested below.
    IDENTITY PRESERVATION: You MUST preserve the fundamental identity and skeletal base of the person. Keep clothing and background intact.
    ${isFullMakeover ? "MODE: FULL PROFESSIONAL MAKEOVER" : "MODE: TARGETED STUDIO EDITING"}

    EDITING PARAMETERS:
    - FACIAL SCULPTING & EYES: ${faceInstruction}
    - HAIR STUDIO: ${hairInstruction}
    - MAKEUP ARTIST (COLOR): ${makeupInstruction}
    - SKIN & COMPLEXION: ${skinInstruction}

    ASSET GUIDE: Base Image is the primary source. Reference Images are for style guidance only.
    OUTPUT: 2K UHD Resolution, photorealistic high-end editorial finish. Ensure perfect edge blending and realistic shadows. If a feature is requested to be preserved, do not modify it.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);

  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "Base Image (Source)" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.editModes.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "Reference Image 1 (Hairstyle Guide)" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.editModes.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "Reference Image 2 (Makeup Guide)" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { StudioSidebar } from './components/StudioSidebar';
import { PreviewCanvas } from './components/PreviewCanvas';
import { ApiKeyModal } from './components/ApiKeyModal';
import { generateBeautyImage, generateBeautyPrompt, analyzeImageAttributes } from './services/geminiService';
import { BeautyState } from './types';
import { INITIAL_FEATURES, INITIAL_HAIR, INITIAL_MAKEUP } from './constants';
import { Sparkles, Upload, Trash2, Zap, Eye, EyeOff, Download, RefreshCcw, Search } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<BeautyState>({
    baseImage: null,
    referenceImages: {
      face: null,
      skin: null,
      hair: null,
      makeup: null
    },
    features: INITIAL_FEATURES,
    skin: { 
      tone: 'natural', 
      texture: ['Smooth'],
      skinAge: 20,
      glowIntensity: 50,
      blemishIntensity: 10
    },
    hair: INITIAL_HAIR,
    makeup: INITIAL_MAKEUP,
    customPrompts: {
      face: '',
      skin: '',
      hair: '',
      makeup: ''
    },
    editModes: {
      face: false,
      skin: false,
      hair: false,
      makeup: false
    },
    aspectRatio: '1:1',
    baseline: undefined
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isComparing, setIsComparing] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setNeedsKey(!hasKey);
      }
    };
    checkKey();
  }, []);

  const applyAnalysis = (data: any) => {
    const skinToneId = data.skinTone < 20 ? 'porcelain' 
                     : data.skinTone < 40 ? 'fair' 
                     : data.skinTone < 60 ? 'natural' 
                     : data.skinTone < 80 ? 'tanned' 
                     : 'deep';

    const hairLen = data.hairLength === 'short' ? 'bob' : data.hairLength === 'medium' ? 'shoulder' : 'long';
    const hairTex = data.hairTexture === 'straight' ? 'straight' : 'waves';

    setState(prev => ({
      ...prev,
      features: {
        ...prev.features,
        eyeSize: data.eyeSize,
        canthalTilt: data.eyeTilt,
        noseBridge: data.noseBridge,
        jawShape: data.jawShape,
        lipThickness: data.lipFullness,
      },
      skin: {
        ...prev.skin,
        tone: skinToneId,
        skinAge: data.skinAge,
      },
      hair: {
        ...prev.hair,
        hairLength: hairLen,
        hairTexture: hairTex,
      },
      baseline: {
        features: {
          eyeSize: data.eyeSize,
          canthalTilt: data.eyeTilt,
          noseBridge: data.noseBridge,
          jawShape: data.jawShape,
          lipThickness: data.lipFullness,
        },
        skin: {
          tone: skinToneId,
          skinAge: data.skinAge,
        },
        hair: {
          hairLength: hairLen,
          hairTexture: hairTex
        }
      }
    }));
  };

  const resetCategory = useCallback((category: 'face' | 'skin' | 'hair' | 'makeup') => {
    setState(prev => {
      const newState = { ...prev };
      const bl = prev.baseline;

      switch (category) {
        case 'face':
          newState.features = {
            ...INITIAL_FEATURES,
            ...(bl?.features || {})
          };
          newState.customPrompts = { ...prev.customPrompts, face: '' };
          break;
        case 'skin':
          newState.skin = {
            ...prev.skin,
            tone: bl?.skin?.tone || 'natural',
            skinAge: bl?.skin?.skinAge || 20,
            glowIntensity: 50,
            blemishIntensity: 10,
            texture: ['Smooth']
          };
          newState.customPrompts = { ...prev.customPrompts, skin: '' };
          break;
        case 'hair':
          newState.hair = {
            ...INITIAL_HAIR,
            hairLength: bl?.hair?.hairLength || INITIAL_HAIR.hairLength,
            hairTexture: bl?.hair?.hairTexture || INITIAL_HAIR.hairTexture
          };
          newState.customPrompts = { ...prev.customPrompts, hair: '' };
          break;
        case 'makeup':
          newState.makeup = INITIAL_MAKEUP;
          newState.customPrompts = { ...prev.customPrompts, makeup: '' };
          break;
      }
      return newState;
    });
  }, []);

  const handleGenerate = async () => {
    try {
      setIsGenerating(true);
      setError(null);
      const result = await generateBeautyImage(state);
      if (result) {
        setGeneratedImage(result);
      } else {
        setError("Synthesis failed. Please check your settings and try again.");
      }
    } catch (err: any) {
      if (err.message?.includes("Requested entity was not found")) {
        setNeedsKey(true);
      }
      setError(err.message || "An error occurred during synthesis.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!generatedImage) return;
    const link = document.createElement('a');
    link.href = generatedImage;
    link.download = `BeautySynth_PRO_2K_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUseAsBase = () => {
    if (!generatedImage) return;
    updateState({ 
      baseImage: generatedImage,
      baseline: undefined 
    });
    setGeneratedImage(null);
    setIsComparing(false);
  };

  const updateState = (updates: Partial<BeautyState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const calculateAspectRatio = (img: HTMLImageElement): "1:1" | "3:4" | "4:3" | "9:16" | "16:9" => {
    const ratio = img.width / img.height;
    const options: { label: "1:1" | "3:4" | "4:3" | "9:16" | "16:9", value: number }[] = [
      { label: "1:1", value: 1 },
      { label: "3:4", value: 0.75 },
      { label: "4:3", value: 1.33 },
      { label: "9:16", value: 0.5625 },
      { label: "16:9", value: 1.777 }
    ];
    return options.reduce((prev, curr) => Math.abs(curr.value - ratio) < Math.abs(prev.value - ratio) ? curr : prev).label;
  };

  const onFileUpload = (type: 'base' | 'face' | 'skin' | 'hair' | 'makeup') => (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        if (type === 'base') {
          const img = new Image();
          img.onload = async () => {
            const ratio = calculateAspectRatio(img);
            updateState({ baseImage: base64String, aspectRatio: ratio, baseline: undefined });

            try {
              setIsAnalyzing(true);
              const analysis = await analyzeImageAttributes(base64String);
              applyAnalysis(analysis);
            } catch (err) {
              console.error("AI Analysis failed:", err);
              setError("AI analysis failed. Please adjust features manually.");
            } finally {
              setIsAnalyzing(false);
            }
          };
          img.src = base64String;
        } else {
          updateState({ 
            referenceImages: { 
              ...state.referenceImages, 
              [type]: base64String 
            } 
          });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const currentPrompt = useMemo(() => generateBeautyPrompt(state), [state]);

  if (needsKey) {
    return <ApiKeyModal onComplete={() => setNeedsKey(false)} />;
  }

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden text-zinc-100">
      <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/80 backdrop-blur-xl z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Sparkles className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight">BeautySynth <span className="text-indigo-500">PRO</span></h1>
            <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">Expert Medical Facial Synthesis</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={handleGenerate}
            disabled={isGenerating || !state.baseImage}
            className={`flex items-center gap-2 px-8 py-2.5 rounded-full font-bold transition-all ${
              isGenerating || !state.baseImage
              ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed opacity-50' 
              : 'bg-indigo-600 hover:bg-indigo-500 text-white active:scale-95 shadow-xl shadow-indigo-600/20'
            }`}
          >
            {isGenerating ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : <Zap className="w-4 h-4 fill-current" />}
            {isGenerating ? 'Synthesizing (2K)...' : 'Generate Synthesis'}
          </button>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <StudioSidebar 
          state={state} 
          updateState={updateState} 
          onRefUpload={onFileUpload} 
          onResetCategory={resetCategory}
        />

        <div className="flex-1 p-6 flex flex-col gap-6 overflow-hidden bg-zinc-950">
          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-xl flex items-center justify-between text-sm shrink-0">
              <span>{error}</span>
              <button onClick={() => setError(null)}>✕</button>
            </div>
          )}

          <div className="flex flex-col flex-1 min-h-0 gap-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-0">
              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative group shadow-inner">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Input: Base Image</h3>
                  <div className="flex items-center gap-2">
                    {isAnalyzing && (
                      <span className="text-[10px] font-bold text-indigo-400 animate-pulse flex items-center gap-1">
                        <Search className="w-3 h-3" /> AI Analyzing...
                      </span>
                    )}
                    {state.baseImage && (
                      <button onClick={() => updateState({ baseImage: null, baseline: undefined })} className="text-zinc-600 hover:text-red-400">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    )}
                  </div>
                </div>
                <div className="flex-1 flex items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-zinc-900 to-black overflow-hidden">
                  {state.baseImage ? (
                    <>
                      <img src={state.baseImage} className={`max-w-full max-h-full object-contain transition-opacity duration-500 ${isAnalyzing ? 'opacity-40 grayscale' : 'opacity-100'}`} alt="Base" />
                      {isAnalyzing && (
                        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                           <div className="w-full h-1 bg-indigo-500/30 overflow-hidden absolute top-0">
                              <div className="w-1/3 h-full bg-indigo-500 animate-[scan_2s_linear_infinite]" />
                           </div>
                           <div className="bg-black/60 backdrop-blur-md px-4 py-2 rounded-full border border-indigo-500/30 shadow-2xl flex items-center gap-2">
                             <div className="w-3 h-3 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin" />
                             <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">Extracting Features</span>
                           </div>
                        </div>
                      )}
                    </>
                  ) : (
                    <label className="cursor-pointer flex flex-col items-center gap-4">
                      <div className="w-20 h-20 rounded-full bg-zinc-800 flex items-center justify-center text-zinc-500 hover:text-indigo-400 transition-colors border border-zinc-700">
                        <Upload className="w-8 h-8" />
                      </div>
                      <span className="text-zinc-500 font-medium text-sm">Upload Base Image</span>
                      <input type="file" className="hidden" accept="image/*" onChange={onFileUpload('base')} />
                    </label>
                  )}
                </div>
              </div>

              <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl overflow-hidden flex flex-col relative shadow-2xl">
                <div className="p-4 border-b border-zinc-800/50 flex justify-between items-center bg-zinc-900/30">
                  <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Synthesis Result: 2K UHD</h3>
                  <div className="flex gap-2">
                    {generatedImage && (
                      <>
                        <button 
                          onClick={handleUseAsBase}
                          className="text-[10px] font-bold uppercase tracking-widest text-indigo-400 flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-500/10 border border-indigo-500/20 active:scale-95 transition-all hover:bg-indigo-500/20"
                          title="Use result as base"
                        >
                          <RefreshCcw className="w-3 h-3" />
                          Use as Base
                        </button>
                        <button 
                          onClick={handleDownload}
                          className="text-[10px] font-bold uppercase tracking-widest text-emerald-400 flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-500/10 border border-emerald-500/20 active:scale-95 transition-all hover:bg-emerald-500/20"
                        >
                          <Download className="w-3 h-3" />
                          Download
                        </button>
                        <button 
                          onMouseDown={() => setIsComparing(true)}
                          onMouseUp={() => setIsComparing(false)}
                          onMouseLeave={() => setIsComparing(false)}
                          className="text-[10px] font-bold uppercase tracking-widest text-zinc-400 flex items-center gap-2 px-3 py-1 rounded-full bg-zinc-500/10 border border-zinc-500/20 active:scale-95 select-none transition-all hover:bg-zinc-500/20"
                        >
                          {isComparing ? <EyeOff className="w-3 h-3" /> : <Eye className="w-3 h-3" />}
                          Compare
                        </button>
                      </>
                    )}
                  </div>
                </div>
                <div className="flex-1 bg-black relative flex items-center justify-center group overflow-hidden">
                  <PreviewCanvas 
                    image={isComparing ? state.baseImage : generatedImage} 
                    loading={isGenerating}
                    onDownload={handleDownload}
                  />
                  {isComparing && (
                    <div className="absolute top-4 left-4 px-3 py-1 bg-black/80 text-[10px] font-bold text-white uppercase tracking-widest rounded-full border border-white/20">
                      Original
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="bg-zinc-900/50 border border-zinc-800/50 rounded-3xl p-4 flex flex-col gap-2 shrink-0 h-28 shadow-inner overflow-hidden">
              <h3 className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                <Zap className="w-3 h-3 text-indigo-500" /> Targeted Synthesis Prompt Preview
              </h3>
              <div className="flex-1 overflow-y-auto text-[11px] text-zinc-400 leading-relaxed font-mono bg-black/30 p-3 rounded-xl border border-zinc-800/50">
                {currentPrompt}
              </div>
            </div>
          </div>
        </div>
      </main>
      <style>{`
        @keyframes scan {
          from { transform: translateX(-100%); }
          to { transform: translateX(300%); }
        }
      `}</style>
    </div>
  );
};

export default App;

