  eyeSize: number;
  lipThickness: number;
  noseWidth: number;
  eyelidType: 'Monolid' | 'Double' | 'Hooded';
  jawlineSharpness: number;
  canthalTilt: number; // eyeTilt
  jawShape: number;
  cheekboneHeight: number;
  faceWidth: number;
  eyeDistance: number;
  noseBridge: number;
  mouthCorners: number;
  lipCupidBow: number;
}

export interface SkinFeatures {
  tone: string;
  texture: string[];
  skinAge: number;
  glowIntensity: number;
  blemishIntensity: number;
}

export interface HairFeatures {
  hairStyle: string;
  hairLength: 'pixie' | 'bob' | 'shoulder' | 'long' | 'extra_long';
  hairTexture: 'straight' | 'c_curl' | 'waves' | 'curly' | 'hippie';
  bangStyle: 'none' | 'see_through' | 'full_blunt' | 'curtain';
  hairVolume: number;
  hairColorTop: string;
  hairColorBottom: string;
}

export interface MakeupFeatures {
  makeupStyle: string;
  eyebrowStyle: 'arched' | 'straight' | 'bushy';
  eyelinerStyle: 'none' | 'thin' | 'winged' | 'smudged';
  eyelashStyle: 'natural' | 'mascara' | 'idol_lashes' | 'false_lashes';
  eyeshadowColor: string;
  eyelinerIntensity: number;
  blushStyle: 'none' | 'apples' | 'drunken' | 'contour';
  blushColor: string;
  blushIntensity: number;
  contourIntensity: number;
  lipStyle: 'matte_full' | 'glossy_full' | 'gradient_tint' | 'overlined';
  lipColor: string;
  lipstickGloss: number;
}

export interface BeautyState {
  baseImage: string | null;
  referenceImages: {
    face: string | null;
    skin: string | null;
    hair: string | null;
    makeup: string | null;
  };
  features: FacialFeatures;
  skin: SkinFeatures;
  hair: HairFeatures;
  makeup: MakeupFeatures;
  customPrompts: {
    face: string;
    skin: string;
    hair: string;
    makeup: string;
  };
  editModes: {
    face: boolean;
    skin: boolean;
    hair: boolean;
    makeup: boolean;
  };
  aspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
  // baseline stores the values detected by AI analysis to enable diff-based prompting
  baseline?: {
    features: Partial<FacialFeatures>;
    skin: Partial<SkinFeatures>;
    hair?: {
      hairLength: HairFeatures['hairLength'];
      hairTexture: HairFeatures['hairTexture'];
    };
  };
}

