                      ))}
                    </div>
                  </div>
                  <div className="space-y-2">
                    <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">Texture</span>
                    <div className="grid grid-cols-3 gap-1">
                      {HAIR_TEXTURES.map(tex => (
                        <button key={tex.id} onClick={() => handleHairChange('hairTexture', tex.id)} className={`py-2 rounded-lg text-[9px] font-bold border transition-all ${state.hair.hairTexture === tex.id ? 'bg-rose-500 text-white border-rose-400' : 'bg-zinc-900/50 border-zinc-800 text-zinc-600'}`}>{tex.label}</button>
                      ))}
                    </div>
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold">
                      <span className="text-zinc-500">Volume</span>
                      <span className="text-rose-400">{state.hair.hairVolume}</span>
                    </div>
                    <input type="range" min="0" max="100" value={state.hair.hairVolume} onChange={(e) => handleHairChange('hairVolume', parseInt(e.target.value))} className="w-full accent-rose-500 h-1 bg-zinc-900 rounded-full appearance-none cursor-pointer" />
                  </div>
