export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, customPrompts, referenceImages, baseline } = state;

  const isFullMakeover = !editModes.face && !editModes.skin && !editModes.hair && !editModes.makeup;
  const targetFace = isFullMakeover || editModes.face;
  const targetSkin = isFullMakeover || editModes.skin;
  const targetHair = isFullMakeover || editModes.hair;
  const targetMakeup = isFullMakeover || editModes.makeup;

  let faceInstruction = "";
  if (targetFace) {
    const faceParts: string[] = [];

    faceParts.push(getDiffFeaturePrompt(features.eyeSize, baseline?.features.eyeSize, 'eye size'));
    faceParts.push(getDiffFeaturePrompt(features.canthalTilt, baseline?.features.canthalTilt, 'eye tilt'));
    faceParts.push(getDiffFeaturePrompt(features.noseBridge, baseline?.features.noseBridge, 'nose bridge'));
    faceParts.push(getDiffFeaturePrompt(features.jawShape, baseline?.features.jawShape, 'jaw shape'));
    faceParts.push(getDiffFeaturePrompt(features.lipThickness, baseline?.features.lipThickness, 'lip thickness'));

    const otherKeys: (keyof FacialFeatures)[] = ['noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'mouthCorners', 'lipCupidBow'];
    otherKeys.forEach(key => {
      const value = features[key];
      if (typeof value === 'number') {
        faceParts.push(getSliderAdjective(value, key));
      }
    });

    // --- 눈썹/아이라인/속눈썹 보존 로직 강화 ---
    let browPrompt = "";
    if (makeup.eyebrowStyle === INITIAL_MAKEUP.eyebrowStyle) {
      browPrompt = "strictly preserve original eyebrows exactly";
    } else {
      switch (makeup.eyebrowStyle) {
        case 'straight': browPrompt = "horizontal linear eyebrows, K-beauty style"; break;
        case 'arched': browPrompt = "high-arched western style eyebrows"; break;
        case 'bushy': browPrompt = "natural bushy texture eyebrows"; break;
      }
    }

    let linerPrompt = makeup.eyelinerStyle === INITIAL_MAKEUP.eyelinerStyle 
      ? "strictly preserve original eyeliner" 
      : `${makeup.eyelinerStyle} eyeliner`;

    let lashPrompt = makeup.eyelashStyle === INITIAL_MAKEUP.eyelashStyle 
      ? "strictly preserve original eyelashes" 
      : `${makeup.eyelashStyle} eyelashes`;

    // --- 쌍꺼풀 변경 지시 정교화 ---
    let eyelidPrompt = "";
    if (features.eyelidType === 'Monolid') {
      eyelidPrompt = "remove any eyelid folds to create a smooth monolid look (single eyelid), but keep the original eye shape and surrounding skin identity";
    } else if (features.eyelidType === 'Double') {
      eyelidPrompt = "add a clear, natural double eyelid fold crease";
    } else {
      eyelidPrompt = "create hooded eyelids with a subtle fold covered by the brow bone";
    }

    faceInstruction = `Facial structure: ${faceParts.join(", ")}. 
      Specific eye modification: ${eyelidPrompt}. 
      Preservation: ${browPrompt}, ${linerPrompt}, and ${lashPrompt}. 
      CRITICAL: Do not darken or change the shape of eyebrows unless explicitly requested. ${customPrompts.face}`;
  } else {
    faceInstruction = "STRICTLY preserve the original facial structure, eye shape, eyebrows, and lashes exactly. Do not modify or enhance them.";
  }

  let skinInstruction = "";
  if (targetSkin) {
    const tone = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const textures = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ");
    const skinToneEmphasized = (baseline?.skin.tone === skin.tone) 
      ? `strictly preserve original ${tone} complexion` 
      : `change complexion to ${tone}`;
    const skinAgePrompt = getDiffFeaturePrompt(skin.skinAge, baseline?.skin.skinAge, 'skin age');

    skinInstruction = `${skinToneEmphasized} with ${textures}. Glow: ${getSliderAdjective(skin.glowIntensity, 'glowIntensity')}, Age: ${skinAgePrompt}, Texture: ${getSliderAdjective(skin.blemishIntensity, 'blemishIntensity')}.`;

    if (skin.texture.includes('Freckles')) {
      skinInstruction += " CRITICAL: Ensure freckles are prominent and not smoothed out.";
    }
    skinInstruction += ` ${customPrompts.skin}`;
  } else {
    skinInstruction = "STRICTLY preserve the original skin tone and texture exactly.";
  }

  let hairInstruction = "";
  if (targetHair) {
    const colorDesc = `ombre hair: ${hair.hairColorTop} to ${hair.hairColorBottom}`;
    const silhouette = `${hair.hairLength} length, ${hair.hairTexture} texture, ${hair.bangStyle} bangs`;
    const volume = getSliderAdjective(hair.hairVolume, 'hairVolume');
    const refText = referenceImages.hair ? "Follow HAIRSTYLE from Ref 1." : `Silhouette: ${silhouette}. Volume: ${volume}.`;
    hairInstruction = `${refText} Color: ${colorDesc}. ${customPrompts.hair}`;
  } else {
    hairInstruction = "STRICTLY preserve original hairstyle and color.";
  }

  let makeupInstruction = "";
  if (targetMakeup) {
    const eyeshadow = `eyeshadow in ${makeup.eyeshadowColor}`;
    const blush = `${makeup.blushStyle} blush: ${makeup.blushColor} at ${makeup.blushIntensity}%`;
    const shading = `contouring: ${getSliderAdjective(makeup.contourIntensity, 'contourIntensity')}`;
    const lips = `${makeup.lipStyle} lips: ${makeup.lipColor}, ${makeup.lipstickGloss}% gloss`;
    const refText = referenceImages.makeup ? "Follow makeup from Ref 2." : `Specs: ${eyeshadow}, ${blush}, ${shading}, ${lips}.`;
    makeupInstruction = `${refText} ${customPrompts.makeup}`;
  } else {
    makeupInstruction = "STRICTLY preserve original eyeshadow, lipstick, and blush colors.";
  }

  return `Act as a world-class professional photo editor. 
    PRIMARY DIRECTIVE: Preserve the person's unique identity, facial bone structure, and original eyebrow shape.
    TASK: Perform targeted surgical edits on the 'Base Image'.

    EDITS:
    - FACE: ${faceInstruction}
    - HAIR: ${hairInstruction}
    - MAKEUP: ${makeupInstruction}
    - SKIN: ${skinInstruction}

    NON-MODIFICATION RULE: If a feature is not explicitly mentioned as needing a 'change', you MUST maintain it exactly as it appears in the Base Image. Do not beautify or enhance unchanged areas.
    OUTPUT: 2K UHD, editorial quality, seamless blending.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "Base Image (Primary Source)" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.editModes.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "Ref 1 (Hair Style)" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.editModes.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "Ref 2 (Makeup Colors)" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

