export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, customPrompts, referenceImages, baseline } = state;

  const isFullMakeover = !editModes.face && !editModes.skin && !editModes.hair && !editModes.makeup;
  const targetFace = isFullMakeover || editModes.face;
  const targetSkin = isFullMakeover || editModes.skin;
  const targetHair = isFullMakeover || editModes.hair;
  const targetMakeup = isFullMakeover || editModes.makeup;

  let faceInstruction = "";
  if (targetFace) {
    const faceParts: string[] = [];

    faceParts.push(getDiffFeaturePrompt(features.eyeSize, baseline?.features.eyeSize, 'eye size'));
    faceParts.push(getDiffFeaturePrompt(features.canthalTilt, baseline?.features.canthalTilt, 'eye tilt/canthal tilt'));
    faceParts.push(getDiffFeaturePrompt(features.noseBridge, baseline?.features.noseBridge, 'nose bridge'));
    faceParts.push(getDiffFeaturePrompt(features.lipThickness, baseline?.features.lipThickness, 'lip thickness/volume'));

    const otherKeys: (keyof FacialFeatures)[] = ['noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'mouthCorners', 'lipCupidBow'];
    otherKeys.forEach(key => {
      const value = features[key];
      if (typeof value === 'number') {
        faceParts.push(getDiffFeaturePrompt(value, (baseline?.features as any)?.[key], key));
      }
    });

    let browPrompt = makeup.eyebrowStyle === INITIAL_MAKEUP.eyebrowStyle 
      ? "strictly preserve original eyebrows exactly" 
      : `${makeup.eyebrowStyle} style eyebrows`;

    let linerPrompt = makeup.eyelinerStyle === INITIAL_MAKEUP.eyelinerStyle 
      ? "strictly preserve original eyeliner" 
      : `${makeup.eyelinerStyle} eyeliner`;

    let lashPrompt = makeup.eyelashStyle === INITIAL_MAKEUP.eyelashStyle 
      ? "strictly preserve original eyelashes" 
      : `${makeup.eyelashStyle} eyelashes`;

    let eyelidPrompt = "";
    if (features.eyelidType === 'Monolid') {
      eyelidPrompt = "completely remove any existing eyelid folds to create a smooth monolid look";
    } else if (features.eyelidType === 'Double') {
      eyelidPrompt = "add a clear and defined double eyelid fold crease";
    } else {
      eyelidPrompt = "create hooded eyelids where the fold is partially covered";
    }

    faceInstruction = `Surgical Facial Reconstruction: ${faceParts.join(", ")}. 
      Eyelid modification: ${eyelidPrompt}. 
      Preservation: ${browPrompt}, ${linerPrompt}, and ${lashPrompt}. 
      CRITICAL: For nose and lips, if the value is extreme, DISREGARD the original shape and reconstruct them with high precision. ${customPrompts.face}`;
  } else {
    faceInstruction = "STRICTLY preserve the original facial structure, eye shape, eyebrows, and lashes exactly.";
  }

  let skinInstruction = "";
  if (targetSkin) {
    const tone = SKIN_TONES.find(t => t.id === skin.tone)?.prompt || "natural skin";
    const textures = skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ");
    const skinToneEmphasized = (baseline?.skin.tone === skin.tone) 
      ? `strictly preserve original ${tone} complexion` 
      : `re-tone the entire skin to ${tone}`;
    const skinAgePrompt = getDiffFeaturePrompt(skin.skinAge, baseline?.skin.skinAge, 'skin age');

    skinInstruction = `${skinToneEmphasized} with ${textures}. Glow: ${getSliderAdjective(skin.glowIntensity, 'glowIntensity')}, Age: ${skinAgePrompt}, Texture: ${getSliderAdjective(skin.blemishIntensity, 'blemishIntensity')}. ${customPrompts.skin}`;
  } else {
    skinInstruction = "STRICTLY preserve the original skin tone and texture exactly.";
  }

  let hairInstruction = "";
  if (targetHair) {
    const colorDesc = `hair color: ${hair.hairColorTop} to ${hair.hairColorBottom} ombre`;
    const silhouette = `${hair.hairLength} length, ${hair.hairTexture} texture, ${hair.bangStyle} bangs`;
    const volume = getSliderAdjective(hair.hairVolume, 'hairVolume');
    const refText = referenceImages.hair ? "Mimic the EXACT hairstyle from Ref 1." : `Style: ${silhouette}. Volume: ${volume}.`;
    hairInstruction = `${refText} ${colorDesc}. ${customPrompts.hair}`;
  } else {
    hairInstruction = "STRICTLY preserve original hairstyle and color.";
  }

  let makeupInstruction = "";
  if (targetMakeup) {
    const eyeshadow = `eyeshadow: ${makeup.eyeshadowColor}`;
    const blush = `${makeup.blushStyle} blush in ${makeup.blushColor} at ${makeup.blushIntensity}% intensity`;
    const shading = `contouring: ${getSliderAdjective(makeup.contourIntensity, 'contourIntensity')}`;
    const lips = `${makeup.lipStyle} lips in ${makeup.lipColor} with ${makeup.lipstickGloss}% gloss`;
    const refText = referenceImages.makeup ? "Apply EXACT makeup colors from Ref 2." : `Makeup specs: ${eyeshadow}, ${blush}, ${shading}, ${lips}.`;
    makeupInstruction = `${refText} ${customPrompts.makeup}`;
  } else {
    makeupInstruction = "STRICTLY preserve original eyeshadow, lipstick, and blush colors.";
  }

  return `Act as a world-class professional cosmetic surgeon and high-end photo retoucher. 
    PRIMARY DIRECTIVE: Follow the surgical instructions precisely. 
    If a facial feature is set to high or low values, perform a BOLD transformation.

    TARGETED EDITS:
    - FACE SCULPTING: ${faceInstruction}
    - HAIR & STYLE: ${hairInstruction}
    - MAKEUP ARTISTRY: ${makeupInstruction}
    - SKIN PERFECTING: ${skinInstruction}

    NON-MODIFICATION RULE: Maintain the base image's lighting and background. Only modify the human subject.
    OUTPUT: Ultra-realistic 2K UHD, editorial perfection, seamless skin blending.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "Primary Base Image to edit" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.editModes.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "Style Reference for Hair" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.editModes.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "Color Reference for Makeup" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

