      case 'hairVolume': return "maximum root lift and hyper-voluminous hair silhouette";
      case 'contourIntensity': return "heavy editorial contouring with deep shadows for skeletal definition";
    }
  }
  if (value <= 20) {
    switch (type) {
      case 'eyeSize': return "smaller refined eye shape with a narrow appearance";
      case 'lipThickness': return "thin minimalist lips; significantly reduce lip volume and border";
      case 'noseWidth': return "pinched slim nasal base; significantly narrow the nostrils and alar base";
      case 'jawlineSharpness': return "soft youthful jawline; smooth out any sharp mandibular angles";
      case 'canthalTilt': return "negative canthal tilt; depress the lateral canthus for a soft drooping puppy-eye look";
      case 'jawShape': return "round organic chin; widen the lower jaw for a soft, curved face shape";
      case 'cheekboneHeight': return "flat suppressed cheekbones; reduce the projection of the mid-face";
      case 'faceWidth': return "ultra-slim and narrow facial contour; drastically reduce the width of the entire face";
      case 'eyeDistance': return "close-set eyes; minimize the intercanthal distance";
      case 'noseBridge': return "low flat nasal profile for a cute, soft facial center";
      case 'mouthCorners': return "downturned mouth corners for a moody pouting expression";
      case 'lipCupidBow': return "straightened round lip line without a defined cupid's bow";
      case 'skinAge': return "flawless youthful baby-skin with zero visible pores or lines";
      case 'glowIntensity': return "completely matte skin with a flat velvet-like finish";
      case 'blemishIntensity': return "perfectly airbrushed skin with 100% blemish removal";
      case 'hairVolume': return "flat sleek hair with zero volume at the crown";
      case 'contourIntensity': return "zero shading; flat natural lighting without makeup contouring";
    }
  }
  return `standard ${type}`;
};

const getDiffFeaturePrompt = (current: number, baseline: number | undefined, type: string): string => {
  if (baseline !== undefined && Math.abs(current - baseline) < 3) {
    return `PIXEL-LOCK: Strictly maintain original ${type} exactly.`;
  }

  const adjective = getSliderAdjective(current, type);
  // 얼굴형 관련 키워드일 경우 '골격 변형'임을 강조
  const isStructural = ['jawShape', 'faceWidth', 'cheekboneHeight', 'jawlineSharpness', 'noseBridge'].includes(type);
  const action = isStructural ? "REMODEL SKELETAL STRUCTURE" : "TRANSFORM FEATURE";
  return `${action}: Physically reshape ${type} to be ${adjective}.`;
};

export const analyzeImageAttributes = async (base64Image: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const [header, data] = base64Image.split(';base64,');
  const mimeType = header.split(':')[1];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data, mimeType } },
          { text: "Analyze the facial features of the person in this image and estimate the following attributes on a scale of 0-100. Return ONLY a JSON object." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            skinTone: { type: Type.NUMBER },
            skinAge: { type: Type.NUMBER },
            eyeSize: { type: Type.NUMBER },
            eyeTilt: { type: Type.NUMBER },
            noseBridge: { type: Type.NUMBER },
            jawShape: { type: Type.NUMBER },
            lipFullness: { type: Type.NUMBER },
            hairLength: { type: Type.STRING, enum: ["short", "medium", "long"] },
            hairTexture: { type: Type.STRING, enum: ["straight", "curly"] }
          },
          required: ["skinTone", "skinAge", "eyeSize", "eyeTilt", "noseBridge", "jawShape", "lipFullness", "hairLength", "hairTexture"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return result;
  } catch (error) {
    console.error("Attribute Analysis Error:", error);
    throw error;
  }
};

export const generateBeautyPrompt = (state: BeautyState): string => {
  const { features, skin, hair, makeup, editModes, customPrompts, referenceImages, baseline } = state;

  const activeCategories = Object.entries(editModes).filter(([_, active]) => active).map(([name]) => name);
  const isTargetedEdit = activeCategories.length > 0;

  let faceInstruction = "";
  if (!isTargetedEdit || editModes.face) {
    const modifications: string[] = [];
    const preservations: string[] = [];

    const featureKeys = ['eyeSize', 'canthalTilt', 'noseBridge', 'lipThickness', 'noseWidth', 'jawlineSharpness', 'cheekboneHeight', 'faceWidth', 'eyeDistance', 'mouthCorners', 'lipCupidBow', 'jawShape'];

    featureKeys.forEach(key => {
      const current = (features as any)[key];
      const bl = (baseline?.features as any)?.[key];
      const instruction = getDiffFeaturePrompt(current, bl, key);

      if (instruction.includes("PIXEL-LOCK")) preservations.push(instruction);
      else modifications.push(instruction);
    });

    faceInstruction = `
      SURGICAL TARGETS (MODIFY THESE NOW): ${modifications.length > 0 ? modifications.join(", ") : "None"}.
      PIXEL ANCHORS (DO NOT TOUCH): ${preservations.join(", ")}.

      SPECIFIC DIRECTIVE FOR FACE SHAPE: If 'jawShape', 'faceWidth', or 'cheekboneHeight' are in SURGICAL TARGETS, you MUST override the original bone structure of the face. Do not let 'PIXEL ANCHORS' prevent these structural changes.
    `;
  }

  let skinInstruction = editModes.skin ? `
    CHANGE SKIN TO: ${SKIN_TONES.find(t => t.id === skin.tone)?.prompt}. 
    TEXTURES: ${skin.texture.map(t => SKIN_TEXTURES.find(st => st.id === t)?.prompt).join(", ")}.
    INTENSITY: Glow ${skin.glowIntensity}, Age ${skin.skinAge}, Texture ${skin.blemishIntensity}.
  ` : "PIXEL-LOCK: Maintain original skin tone and texture perfectly.";

  let hairInstruction = editModes.hair ? `
    MODIFY HAIRSTYLE: ${hair.hairLength}, ${hair.hairTexture}, ${hair.bangStyle} bangs. Volume ${hair.hairVolume}.
    COLOR: Ombre from ${hair.hairColorTop} to ${hair.hairColorBottom}.
  ` : "PIXEL-LOCK: Maintain original hair shape and color exactly.";

  let makeupInstruction = editModes.makeup ? `
    APPLY MAKEUP: ${makeup.makeupStyle} style. Eyeshadow ${makeup.eyeshadowColor}, Blush ${makeup.blushColor} (${makeup.blushStyle}), Lips ${makeup.lipColor} (${makeup.lipStyle}).
  ` : "PIXEL-LOCK: Maintain original makeup or bare face.";

  return `Act as a world-class Surgical Retoucher. 
    PRIMARY MISSION: Perform targeted anatomical changes while preserving the subject's identity in all 'PIXEL-LOCK' areas.

    RULES OF ENGAGEMENT:
    - You are a plastic surgeon. If a face shape attribute is modified, physically move the jaw, chin, and cheekbones.
    - Identity preservation is key, but it must not be an excuse to ignore requested structural transformations.

    EXECUTION DETAILS:
    - FACE: ${faceInstruction}
    - SKIN: ${skinInstruction}
    - HAIR: ${hairInstruction}
    - MAKEUP: ${makeupInstruction}

    The final output must be 2K UHD, look like a professional editorial photo, and maintain the exact lighting and background of the Base Image.`;
};

export const generateBeautyImage = async (state: BeautyState): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = generateBeautyPrompt(state);
  const parts: any[] = [{ text: prompt }];

  if (state.baseImage) {
    const baseData = state.baseImage.split(',')[1];
    const mimeType = state.baseImage.split(';')[0].split(':')[1];
    parts.push({ text: "INPUT BASE IMAGE" });
    parts.push({ inlineData: { data: baseData, mimeType } });
  }

  if (state.editModes.hair && state.referenceImages.hair) {
    const data = state.referenceImages.hair.split(',')[1];
    const mimeType = state.referenceImages.hair.split(';')[0].split(':')[1];
    parts.push({ text: "HAIRSTYLE REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.editModes.makeup && state.referenceImages.makeup) {
    const data = state.referenceImages.makeup.split(',')[1];
    const mimeType = state.referenceImages.makeup.split(';')[0].split(':')[1];
    parts.push({ text: "MAKEUP REFERENCE" });
    parts.push({ inlineData: { data, mimeType } });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: state.aspectRatio,
          imageSize: "2K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};
